var CONTENT={patterns:[{id:'what-clicked-for-me',phrase:'What clicked for me was...',category:'self-description',difficulty:1,examples:['What clicked for me was realizing that coding agents let me build software tailored to a team\'s exact workflow.','What clicked for me was that we didn\'t need better tools — we needed a completely different workflow.','What clicked for me was that the real bottleneck wasn\'t technology, it was how the team communicated requirements.'],explanation:'Use this to explain a key realization or motivation. It\'s more natural than \'I realized\' and signals genuine insight.',when_to_use:'Explaining career pivots, project origins, or why you chose an unconventional approach.'},{id:'what-im-looking-for',phrase:'What I\'m really looking for is...',category:'self-description',difficulty:1,examples:['What I\'m really looking for is a team where AI tooling is a strategic priority, not a side project.','What I\'m really looking for is the chance to build platforms that impact thousands of engineers, not dozens.','What I\'m really looking for is the complexity of fintech combined with the speed of an AI-native company.'],explanation:'States your goals clearly and with conviction. Much stronger than \'I want to work on interesting problems.\'',when_to_use:'Answering \'what are you looking for?\' or \'why this company?\''},{id:'over-time-i-became',phrase:'Over time I became the...',category:'self-description',difficulty:1,examples:['Over time I became the AI pioneer in the organization, even though that wasn\'t my original role.','Over time I became the person teams came to when they needed to automate something that seemed impossible.','Over time I became the bridge between the security team and the platform engineering group.'],explanation:'Shows growth trajectory. More natural than listing promotions or title changes.',when_to_use:'Walk me through your background. Tell me about yourself.'},{id:'the-way-i-see-it',phrase:'The way I see it is...',category:'opinion-stating',difficulty:1,examples:['The way I see it is, we should optimize for latency first and add caching layers later.','The way I see it is, this trade-off favors reliability over raw speed at our current scale.','The way I see it is, the team needs clarity on priorities more than another tool right now.'],explanation:'States an opinion without sounding rigid. Signals \'this is my view but I\'m open to discussion.\'',when_to_use:'Design discussions, code review disagreements, stakeholder proposals, system design interviews.'},{id:'id-argue-that',phrase:'I\'d argue that...',category:'opinion-stating',difficulty:2,examples:['I\'d argue that we should solve the data consistency problem first before adding more services.','I\'d argue that this approach is simpler to maintain, even if it takes slightly longer to build initially.','I\'d argue that the cost of not doing this is higher than the cost of doing it.'],explanation:'Stronger than \'I think\' but still respectful. Invites counterargument rather than shutting down discussion.',when_to_use:'When you have conviction about a decision but want to remain collaborative.'},{id:'i-see-it-differently',phrase:'I see it a bit differently...',category:'opinion-stating',difficulty:2,examples:['I see it a bit differently — I think the bottleneck is in the data layer, not the API layer.','I see it a bit differently. The customer impact is bigger than the engineering effort here.','I see it a bit differently. We might be optimizing for a problem we don\'t have yet.'],explanation:'The gentlest way to disagree. \'A bit\' softens it. Opens a conversation rather than starting an argument.',when_to_use:'Disagreeing with peers, especially in cross-functional settings where relationships matter.'},{id:'that-said',phrase:'That said...',category:'transitional',difficulty:2,examples:['That said, the trade-off was worth it given the timeline we were working with.','That said, I\'d do the migration differently if I were starting today.','That said, the approach worked well for our scale and I\'d recommend it for similar situations.'],explanation:'Introduces a counterpoint or qualification. More natural than \'however\' in speech.',when_to_use:'After making a strong point, when you want to acknowledge the other side.'},{id:'building-on-that',phrase:'Building on that...',category:'transitional',difficulty:1,examples:['Building on that, we also realized the same pattern applied to our deployment pipeline.','Building on that, the next logical step was to apply the same approach to the mobile team.','Building on that, the feedback from the first rollout directly shaped the second version.'],explanation:'Connects two ideas smoothly. Shows you\'re thinking in systems, not isolated anecdotes.',when_to_use:'When you want to show how one project led to another, or how a pattern generalized.'},{id:'the-other-piece-was',phrase:'The other piece was...',category:'transitional',difficulty:1,examples:['The other piece was security. We couldn\'t just automate — we had to do it safely.','The other piece was getting buy-in from the BA team. The technology was the easy part.','The other piece was making sure the solution would scale beyond my own team.'],explanation:'Introduces a second dimension. Great for showing you think about problems holistically.',when_to_use:'When telling a story with multiple workstreams or considerations.'},{id:'what-id-highlight',phrase:'What I\'d really highlight is...',category:'emphasis',difficulty:1,examples:['What I\'d really highlight is that the adoption was organic — nobody mandated these tools.','What I\'d really highlight is how the team\'s velocity changed after we rebuilt the workflow.','What I\'d really highlight is that we achieved this with zero additional infrastructure cost.'],explanation:'Directs attention to the most important part. Shows you know what matters and what\'s detail.',when_to_use:'When a story has multiple results and you want to emphasize the main one.'},{id:'the-key-thing-is',phrase:'The key thing to understand is...',category:'emphasis',difficulty:1,examples:['The key thing to understand is that the agents don\'t just automate tasks — they shape what gets built.','The key thing to understand is that we weren\'t replacing anyone\'s job. We were removing the boring parts.','The key thing to understand is that the 80 percent reduction came from the workflow change, not the AI alone.'],explanation:'Signals you\'re about to say something important. Makes the listener lean in.',when_to_use:'When explaining something counterintuitive or easily misunderstood.'},{id:'to-put-a-finer-point-on-it',phrase:'To put a finer point on it...',category:'refining',difficulty:3,examples:['To put a finer point on it — we didn\'t just speed up triage. We eliminated the need for manual triage entirely.','To put a finer point on it — the real innovation wasn\'t the AI. It was redesigning the workflow around what AI could do.','To put a finer point on it — this wasn\'t about tools. This was about changing how the team thought about automation.'],explanation:'Refines a previous statement to be more precise or impactful. Shows you\'re thinking critically about your own words.',when_to_use:'When you want to sharpen a point you just made. Especially effective in closing statements.'},{id:'let-me-recenter',phrase:'Let me re-center. The core question is...',category:'refining',difficulty:2,examples:['Let me re-center. The core question is whether this architecture can handle our growth over the next 18 months.','Let me re-center. What we\'re really trying to decide is whether to build or buy this capability.','Let me re-center. The fundamental trade-off here is speed versus correctness.'],explanation:'Recovers from going off track. Mid-sentence stop, anchor back to the main question, restart with structure.',when_to_use:'When you realize mid-answer that you\'re rambling or going off on a tangent.'},{id:'the-crux-of-it',phrase:'The crux of it is...',category:'refining',difficulty:2,examples:['The crux of it is that our connection pool was configured for peak traffic but not for the idle timeout behavior of the new database version. Everything else was a symptom.','The crux of it is that we needed to trust the AI\'s diagnosis before developers would use it.','The crux of it is that security and velocity weren\'t actually in conflict — they were both blocked by the same bottleneck.'],explanation:'Gets to the absolute core of an issue in one phrase. Forces you to find the essence.',when_to_use:'When an answer is getting complex and you need to land the main point.'},{id:'i-havent-worked-with-that',phrase:'I haven\'t worked directly with that. What I can tell you is...',category:'bridging',difficulty:2,examples:['I haven\'t worked directly with Kubernetes at that scale. What I can tell you is that I\'ve designed distributed systems handling 50K requests per second, and the scheduling and networking concepts transfer directly.','I haven\'t worked directly with Golang in production. What I can tell you is that I\'ve built systems in Kotlin, Rust, and Python, and my ramp-up pattern is consistent across languages.'],explanation:'Honest about gaps, confident about adjacent experience. Transforms a weakness into a demonstration of learning ability.',when_to_use:'When asked about a technology or experience you genuinely don\'t have.'},{id:'heres-how-id-ramp-up',phrase:'Here\'s how I\'d ramp up on that...',category:'bridging',difficulty:2,examples:['Here\'s how I\'d ramp up on that. I\'d start by reading the existing architecture decisions and PRs from the last quarter to understand the patterns. Then I\'d pair with someone on the team for the first week.','Here\'s how I\'d ramp up on that. I learn best by building. I\'d take a small, well-defined task and work through it end to end, asking for code review at each step.'],explanation:'Shows you have a repeatable learning process. More convincing than \'I\'m a fast learner.\'',when_to_use:'Follow-up to acknowledging a gap. Shows you\'re proactive about closing it.'},{id:'this-resulted-in',phrase:'This resulted in...',category:'impact',difficulty:1,examples:['This resulted in the CVE workload dropping by 80 percent within the first month.','This resulted in the BA team adopting the agents without any formal rollout — they just started using them.','This resulted in us shipping the migration three weeks ahead of schedule with zero data issues.'],explanation:'Simple, direct cause-to-effect. Always follow with a number or specific outcome.',when_to_use:'Closing any STAR story. The Result section.'},{id:'before-this-after-this',phrase:'Before this... After this...',category:'impact',difficulty:1,examples:['Before this, triaging a single CVE took about 45 minutes. After this, it took under 5.','Before this, the BA team spent three days producing reports manually. After this, it runs in under 30 minutes.','Before this, developers avoided the security review process. After this, they proactively requested it.'],explanation:'The simplest and most powerful impact pattern. Before/after contrast creates an instant mental picture of the change.',when_to_use:'Whenever you have a measurable improvement to describe.'},{id:'the-lesson-i-took',phrase:'The lesson I took away was...',category:'impact',difficulty:1,examples:['The lesson I took away was that adoption is a design problem, not a communication problem. If you build the right thing, people use it.','The lesson I took away was that you can\'t bolt AI onto a broken workflow. You have to rethink the workflow first.','The lesson I took away was that the hardest part of internal tooling isn\'t the technology — it\'s understanding the existing workflow deeply enough to improve it.'],explanation:'Ends every story with a generalizable insight. The difference between \'something that happened to me\' and \'a pattern I now recognize.\'',when_to_use:'End of every STAR-LA answer. The Learning and Application sections.'},{id:'to-give-you-a-concrete-example',phrase:'To give you a concrete example...',category:'elaboration',difficulty:1,examples:['To give you a concrete example — one BA spent two days a week compiling data from five different systems. The agent now does it in 30 minutes while she focuses on analysis.','To give you a concrete example — we found a vulnerability in a library that our commercial scanner had missed for six months. The AI flagged it because it understood how we were actually using that library.'],explanation:'Bridges from abstract claim to specific evidence. Makes your answer tangible.',when_to_use:'After making a general claim. The interviewer needs evidence, not assertions.'},{id:'what-that-looked-like-in-practice',phrase:'What that looked like in practice was...',category:'elaboration',difficulty:2,examples:['What that looked like in practice was a dashboard that developers checked every morning instead of a Jira queue they dreaded.','What that looked like in practice was the BA team building their own agent customizations without asking me for help.'],explanation:'Turns abstract descriptions into concrete scenes. Makes your story visual.',when_to_use:'When you\'ve described a system or process and want to make it feel real.'},{id:'thats-a-great-question',phrase:'That\'s a great question. Let me think about that for a moment.',category:'thinking-time',difficulty:1,examples:['That\'s a great question. Let me think about that for a moment... [3 second pause] So, the situation was...'],explanation:'Buying time without sounding lost. Acknowledges the question, signals you\'re being thoughtful, gives you 3-4 seconds to structure.',when_to_use:'Any unexpected question. Always say this instead of \'um\' or \'hmm.\''},{id:'im-glad-you-asked-that',phrase:'I\'m glad you asked that.',category:'thinking-time',difficulty:1,examples:['I\'m glad you asked that. It\'s something I\'ve thought about a lot because...','I\'m glad you asked that. It actually connects to a broader point about how we think about automation.'],explanation:'Warmth + confidence. Turns a potentially challenging question into a welcome invitation.',when_to_use:'When you have a strong answer ready. Especially for \'why are you leaving\' or \'tell me about a weakness.\''},{id:'one-thing-i-wish-id-known',phrase:'One thing I wish I\'d known earlier was...',category:'self-description',difficulty:1,examples:['One thing I wish I\'d known earlier was that the best way to get promoted is to make your manager\'s priorities your priorities.','One thing I wish I\'d known earlier was that asking for help isn\'t a weakness — it\'s how you scale your impact beyond your own capacity.','One thing I wish I\'d known earlier was that the most impactful work is rarely the most technically interesting work.'],explanation:'Shows self-awareness and growth. Reveals maturity without boasting.',when_to_use:'\'What would you tell your younger self?\' or when reflecting on lessons learned.'},{id:'my-approach-is',phrase:'My approach to [X] is...',category:'self-description',difficulty:1,examples:['My approach to debugging production issues is to start from the symptoms and work backwards to the root cause, always looking for the simplest explanation first.','My approach to code review is to understand the intent before evaluating the implementation. If I don\'t know what problem they\'re solving, I can\'t judge if the solution is right.','My approach to technical debt is to treat it like a credit card — fine to carry a balance, but you need a plan to pay it down before the interest compounds.'],explanation:'Signals you have a repeatable, thoughtful process. More convincing than \'I\'m methodical.\'',when_to_use:'\'How do you handle X?\' questions where X is debugging, code review, prioritization, etc.'},{id:'i-draw-the-line-at',phrase:'I draw the line at...',category:'opinion-stating',difficulty:2,examples:['I draw the line at shipping known data-loss bugs. Speed is important, but not at the cost of customer trust.','I draw the line at making commitments to stakeholders without consulting the team first. That\'s how you get burnout and missed deadlines.','I draw the line at skipping on-call handoff documentation. The fifteen minutes you save costs the next person hours.'],explanation:'Shows you have clear professional boundaries. Signals integrity and values without being preachy.',when_to_use:'When discussing ethics, quality standards, or situations where you pushed back.'},{id:'the-unpopular-position',phrase:'I know this might be unpopular, but...',category:'opinion-stating',difficulty:2,examples:['I know this might be unpopular, but I think we should slow down the hiring and invest in onboarding first.','I know this might be unpopular, but I believe rewriting from scratch is almost always the wrong choice. There\'s more domain knowledge in that code than you think.','I know this might be unpopular, but I\'d rather ship a v1 that\'s ugly and working than spend three months making it elegant.'],explanation:'Pre-frames dissent as humility rather than combativeness. Makes the listener more receptive.',when_to_use:'When you need to disagree with the prevailing opinion in a group.'},{id:'at-a-high-level',phrase:'At a high level...',category:'structural',difficulty:1,examples:['At a high level, there are three components: a rate limiter, a request router, and a fallback handler.','At a high level, the system works like a publish-subscribe model where producers write to topics and consumers read from them.','At a high level, our migration strategy was to run both systems in parallel, shadow traffic to the new system, and cutover once we hit parity.'],explanation:'Starts with the big picture before diving into details. Shows you think top-down, which is how senior engineers communicate.',when_to_use:'System design interviews, architecture discussions, any complex explanation.'},{id:'the-first-thing-i-would',phrase:'The first thing I would do is...',category:'structural',difficulty:1,examples:['The first thing I would do is clarify the requirements and constraints. Who are the users? What\'s the expected scale? What are the SLAs?','The first thing I would do is identify the bottleneck. Until you know where the system is slow, you\'re guessing at solutions.','The first thing I would do is look at the error rates and latency percentiles. The data will tell you where to focus.'],explanation:'Shows you have a systematic starting point. Prevents you from jumping to solutions before understanding the problem.',when_to_use:'System design, debugging, or any \'how would you approach X?\' question.'},{id:'there-are-three-things',phrase:'There are three things to consider here...',category:'structural',difficulty:1,examples:['There are three things to consider here: availability, consistency, and latency — and we can only optimize for two of them at any given scale.','There are three things to consider here: the read path, the write path, and the consistency model between them.','There are three things to consider here: what the user sees, what the system stores, and how we keep them in sync.'],explanation:'Forces structured thinking. Three is a magic number — enough to show depth, not so many that you lose the audience.',when_to_use:'Any open-ended design or architecture question.'},{id:'the-trade-off-here-is',phrase:'The trade-off here is...',category:'analysis',difficulty:2,examples:['The trade-off here is between consistency and availability. If we accept eventual consistency, we can serve reads from the nearest replica.','The trade-off here is between simplicity and flexibility. A monolith is easier to deploy and debug, but microservices let teams move independently.','The trade-off here is between indexing speed and query performance. More indexes mean faster reads but slower writes and more storage.'],explanation:'Every engineering decision involves trade-offs. Naming them shows you think in terms of constraints, not just solutions.',when_to_use:'System design interviews, architecture discussions, any decision-making scenario.'},{id:'if-we-zoom-out',phrase:'If we zoom out for a moment...',category:'structural',difficulty:2,examples:['If we zoom out for a moment, what we\'re really building is an event-driven architecture where every service reacts to changes in state.','If we zoom out for a moment, the core problem is that we have multiple producers writing to the same data store without coordination.','If we zoom out for a moment, the entire system can be modeled as a pipeline: ingest, process, store, serve.'],explanation:'Pulls the conversation up to the architecture level when it\'s getting bogged down in implementation details.',when_to_use:'When a system design discussion is getting lost in the weeds.'},{id:'the-simpler-approach',phrase:'The simpler approach would be to...',category:'analysis',difficulty:2,examples:['The simpler approach would be to use a single database with read replicas and only introduce caching if we hit performance issues at scale.','The simpler approach would be to batch the writes and flush every 5 seconds instead of trying to maintain real-time consistency across regions.','The simpler approach would be to use an off-the-shelf message queue rather than building our own event bus.'],explanation:'Shows engineering pragmatism. Senior engineers default to simple solutions and add complexity only when justified by data.',when_to_use:'When you or the interviewer are over-engineering a solution.'},{id:'the-failure-mode-is',phrase:'The failure mode I\'m most concerned about is...',category:'analysis',difficulty:2,examples:['The failure mode I\'m most concerned about is a thundering herd when the cache expires — all requests hit the database simultaneously.','The failure mode I\'m most concerned about is split-brain in the leader election — two nodes both think they\'re primary.','The failure mode I\'m most concerned about is cascading retries — a downstream slowdown causes upstream timeouts, which cause more retries, which make it worse.'],explanation:'Demonstrates operational maturity. Shows you think about what can go wrong, not just what should go right.',when_to_use:'System design interviews, reliability discussions, any architecture review.'},{id:'we-can-mitigate-that-by',phrase:'We can mitigate that by...',category:'analysis',difficulty:2,examples:['We can mitigate that by implementing circuit breakers — if a downstream service fails three times in a row, we stop sending traffic and return a fallback response.','We can mitigate that by adding jitter to our cache TTLs so they don\'t all expire at the same time.','We can mitigate that by using a leader lease with a fencing token — even if a stale leader tries to write, the storage layer will reject it.'],explanation:'Follows up on identifying a failure mode with a concrete solution. The full pattern is: identify the risk, then address it.',when_to_use:'Immediately after naming a failure mode in a system design interview.'},{id:'under-normal-conditions',phrase:'Under normal conditions, X. Under edge cases, Y...',category:'analysis',difficulty:3,examples:['Under normal conditions, we serve from cache with sub-millisecond latency. Under edge cases — cache miss or stampede — we have a request coalescing layer that ensures only one request hits the database.','Under normal conditions, the primary handles all writes. Under edge cases — primary failure — the replica takes over within 30 seconds using a consensus protocol.','Under normal conditions, we process events in order. Under edge cases — network partition — we use sequence numbers to detect and reconcile gaps.'],explanation:'Shows you understand that systems behave differently at the edges. Distinguishes between happy path and failure path thinking.',when_to_use:'System design, explaining how a system handles failures.'},{id:'at-our-scale',phrase:'At our scale, we had to...',category:'impact',difficulty:2,examples:['At our scale, we had to shard the database by tenant ID because no single Postgres instance could handle 50K writes per second.','At our scale, we had to move from synchronous replication to asynchronous because the cross-region latency was killing our write throughput.','At our scale, we had to build our own deployment orchestrator because none of the off-the-shelf tools could handle rolling out to 10,000 servers safely.'],explanation:'Contextualizes technical decisions in terms of scale. Shows that your architecture choices were driven by real constraints, not resume-driven development.',when_to_use:'Explaining why you chose a particular architecture or technology.'},{id:'the-principle-behind',phrase:'The principle behind this is...',category:'analysis',difficulty:2,examples:['The principle behind this is that you should never block a request on a slow operation. Do the minimum work synchronously and defer everything else to an async pipeline.','The principle behind this is that data should be stored once and derived everywhere. We write to the source of truth and compute views from it.','The principle behind this is that every component should be able to fail without taking down the entire system. Blast radius minimization.'],explanation:'Elevates a specific decision to a general principle. Shows you can abstract from experience — a Staff-level signal.',when_to_use:'After explaining a specific architecture choice or pattern, connect it to a deeper principle.'},{id:'a-real-world-example',phrase:'A real-world example of this is...',category:'elaboration',difficulty:1,examples:['A real-world example of this is how Netflix uses chaos engineering — they intentionally break things in production to verify their resilience patterns work.','A real-world example of this is how Amazon does two-pizza teams — each team owns their service end-to-end, from design to on-call.','A real-world example of this is how Stripe handles idempotency — every API request gets a key, and the same key always returns the same result.'],explanation:'Grounds abstract concepts in recognizable industry examples. Shows you study how real systems work.',when_to_use:'System design interviews when you need to justify an approach.'},{id:'what-surprised-me',phrase:'What surprised me was...',category:'self-description',difficulty:1,examples:['What surprised me was how much of production reliability is about monitoring and alerting, not about writing bug-free code.','What surprised me was that the hardest part of the migration wasn\'t the technology — it was getting people to trust the new system.','What surprised me was that the best optimization we made wasn\'t technical at all — it was reordering the steps in the user workflow.'],explanation:'Shows humility and intellectual curiosity. Surprises signal learning, not ignorance.',when_to_use:'Reflecting on a project, answering \'what did you learn?\''},{id:'looking-back',phrase:'Looking back, I would...',category:'refining',difficulty:2,examples:['Looking back, I would have invested more in observability from day one. We spent months flying blind.','Looking back, I would have started with a simpler architecture and evolved it based on actual traffic patterns rather than theoretical ones.','Looking back, I would have involved the QA team earlier. They caught issues in week one that we didn\'t find until week six.'],explanation:'Shows growth and self-awareness. Hindsight framed as learning, not regret.',when_to_use:'Reflecting on a project or decision, post-mortem discussions.'}],tips:[{id:'four-second-pause',name:'4-Second Pause Protocol',category:'thinking-out-loud',duration_min:3,segments:['Second one: Breathe. Don\'t rush to fill the silence.','Second two: Identify what competency they are actually testing.','Second three: Pick the closest relevant story you have.','Second four: Lock in your opening sentence and start.'],explanation:'When you get an unexpected question, four seconds of structured thinking produces a better answer than four seconds of rambling.'},{id:'structure-first',name:'Structure-First Approach',category:'thinking-out-loud',duration_min:3,segments:['Before answering, tell the interviewer how you\'ll structure your response.','Say: \'I\'ll walk you through this in three parts. First the situation, then what I did, and finally the outcome.\'','This does three things at once: shows organized thinking, gives the interviewer a mental map, and keeps you on track.'],explanation:'Stating your structure before your content makes you sound organized even before you\'ve said anything substantive.'},{id:'verbal-signposting',name:'Verbal Signposting',category:'thinking-out-loud',duration_min:3,segments:['Learn 7 signpost phrases that make anything you say sound more organized.','\'There are three things at play here.\' \'The crux of it is.\' \'Let me pressure-test that.\' \'Another way to frame this is.\' \'The trade-off I\'m making is.\' \'If I step back for a moment.\' \'To put a finer point on it.\'','These work because they tell the listener where you are in your thought process.'],explanation:'Signposts are the verbal equivalent of headings in a document. They tell the listener where you are and where you\'re going.'},{id:'pause-and-anchor',name:'Pause-and-Anchor Technique',category:'thinking-out-loud',duration_min:3,segments:['You\'re mid-sentence and realize you\'re going off track. Don\'t keep talking.','Stop. Mid-sentence is fine. Better than another 30 seconds of rambling.','Say: \'Let me re-center. The core question is actually...\'','Then restart with your structure.'],explanation:'The ability to notice you\'re off track and recover gracefully is a stronger signal than never going off track.'},{id:'star-la',name:'STAR-LA Framework',category:'story-structure',duration_min:4,segments:['Situation — Set the scene in 1-2 sentences.','Task — What was your responsibility? 1 sentence.','Action — What you specifically did. Use I not we. 3-4 sentences. This is 50% of the answer.','Result — Quantified outcome. 2 sentences with numbers.','Learning — What principle did you extract? 1-2 sentences.','Application — How have you applied this since? 1-2 sentences.','Total target: 90-120 seconds. The LA part is what makes this a Staff-level answer.'],explanation:'STAR is the baseline. Adding Learning and Application shows you extract principles from experience and propagate them — that\'s the Staff engineer job.'},{id:'question-deconstruction',name:'3-Layer Question Deconstruction',category:'story-structure',duration_min:4,segments:['Every question has three layers.','Layer 1: the surface ask. The words they actually said.','Layer 2: the competency being tested. What trait does a perfect answer demonstrate?','Layer 3: the Staff-level dimension. How does this show organizational impact, not just personal achievement?'],explanation:'Answering the surface question gets you \'meets expectations.\' Answering the subtext gets you \'strong hire.\''},{id:'i-dont-know-bridging',name:'Three Ways to Say I Don\'t Know',category:'bridging',duration_min:4,segments:['Never just say \'I don\'t know\' and stop. Transform ignorance into demonstrated problem-solving.','Honest Redirect: \'I don\'t know that specific answer, but here\'s the closest analogue from my experience.\'','Principle-Based: \'I haven\'t faced that exact situation, but my operating principle in similar contexts is...\'','Strength Pivot: \'I haven\'t worked directly with X. However, when I ramped up on Y, here\'s the approach I used.\''],explanation:'Strong candidates don\'t know everything. They know how to figure things out and can articulate that process.'},{id:'hook-flow-landing',name:'Hook-Flow-Landing Structure',category:'story-structure',duration_min:4,segments:['Hook — your first 10 seconds. Start with the most interesting element. Never lead with background.','Weak hook: \'In 2023 I was working at GBST on the tax team and we had this database...\'','Strong hook: \'We discovered we\'d been silently dropping transactions for two weeks. I was the engineer on call.\'','Flow — 60-90 seconds. Chronological. Cut every detail that doesn\'t serve the point.','Landing — your last 15 seconds. \'The reason I tell this story is that it fundamentally changed how I think about observability.\''],explanation:'Interviewers see 5-8 candidates. Your story needs to grab attention in the first 10 seconds and leave a takeaway in the last 15.'},{id:'acknowledge-reframe',name:'Acknowledge-Reframe Bridge',category:'bridging',duration_min:3,segments:['For when a question exposes a genuine weakness.','Step 1: Acknowledge honestly. \'I\'m glad you asked that. I haven\'t operated Kubernetes at the scale you\'re describing.\'','Step 2: Reframe to adjacent strength. \'What I can tell you is that I\'ve designed distributed systems handling 50K requests per second.\'','Step 3: Describe your plan. \'I\'ve been systematically working through Production Kubernetes and running a home cluster.\''],explanation:'Honest about gaps, confident about adjacent experience, proactive about closing the gap. Three signals in one answer.'},{id:'so-what-test',name:'The So What Test',category:'story-structure',duration_min:3,segments:['After every answer, the interviewer should never wonder \'so what?\' Pre-empt it.','After telling your story, add one sentence: \'This matters because it demonstrates that I can take something from idea to production adoption across multiple teams.\'','This is not arrogance. It\'s clarity. You\'re connecting the dots for them.'],explanation:'The strongest candidates explicitly state what their story proves. Don\'t make the interviewer infer.'},{id:'system-design-framework',name:'System Design Interview Framework (RESHADED)',category:'system-design',duration_min:5,segments:['Requirements: clarify functional and non-functional requirements. Ask about scale, latency, availability.','Estimation: back-of-envelope calculations — QPS, storage, bandwidth, memory.','Storage schema: design the data model — tables, indexes, relationships.','High-level architecture: draw the boxes and arrows — clients, services, databases, caches.','API design: define the endpoints and data contracts.','Detailed design: dive deep into the most interesting component — caching, sharding, replication.','Evaluate trade-offs: explicitly name the trade-offs in your design and justify your choices.'],explanation:'A systematic framework prevents you from going off track and ensures you cover all the dimensions the interviewer is looking for.'},{id:'trade-off-vocabulary',name:'Trade-Off Vocabulary for System Design',category:'system-design',duration_min:3,segments:['Consistency vs Availability (CAP)','Latency vs Throughput','Simplicity vs Flexibility','Cost vs Performance','Reliability vs Complexity','Strong consistency vs Eventual consistency','Pull vs Push','Normalization vs Denormalization','Stateful vs Stateless','Batch vs Real-time'],explanation:'Being able to name trade-offs precisely is more impressive than hand-waving. Practice saying: \'The trade-off here is X versus Y, and I chose X because...\''},{id:'estimation-cheat-sheet',name:'Back-of-Envelope Estimation Cheat Sheet',category:'system-design',duration_min:3,segments:['Numbers every engineer should know: L1 cache ~1ns, L2 ~4ns, RAM ~100ns, SSD ~16us, HDD ~4ms, Network same datacenter ~500us, Network same region ~5ms, Network cross-region ~150ms','Rule of thumb: 1 million requests/day ~12 RPS average, 100M/day ~1200 RPS','Storage: 1 byte * 1M users = 1MB, 1KB * 1B users = 1TB','Bandwidth: 1MB response * 1000 RPS = 1GB/s outbound','Availability: 99.9% = 8.7 hours downtime/year, 99.99% = 52.6 minutes, 99.999% = 5.26 minutes'],explanation:'Quick estimation skills let you make informed design decisions on the spot. Interviewers love candidates who can reason about scale.'}],prompts:[{id:'quick-decision',text:'Tell me about a time you had to make a quick decision with limited information.',competency:'judgment-under-pressure',framework:'STAR-LA',patterns:['That\'s a great question. Let me think about that for a moment...','The key thing to understand is...','This resulted in...'],structure:['Pause 4 seconds. Name the decision context','Situation: what was urgent, what info was missing','Action: what you decided and why — name the trade-off','Result: outcome with a number','Learning: the principle you now apply to fast decisions'],sample_answer:'I was on call at 2 AM when our primary database started rejecting connections. We had 3 options: failover to replica (risk of data gap), restart the primary (risk of longer outage), or do nothing and hope it self-heals. I had no runbook for this exact scenario. I chose failover because partial availability beats total outage. The failover took 90 seconds. We lost 12 seconds of writes, but restored service within 2 minutes. The lesson I took away was that when information is incomplete, optimize for reversibility — failover could be reversed, but waiting made the problem worse.',pitfalls:['Don\'t describe a trivial decision (what to order for lunch)','Don\'t skip the trade-off — they want to see how you weigh options','Don\'t say \'I just went with my gut\' without explaining what informed your gut']},{id:'disagreement',text:'Tell me about a time you disagreed with a senior stakeholder.',competency:'courageous-communication',framework:'STAR-LA + Acknowledge-Reframe',patterns:['The way I see it is...','I\'d argue that...','That said...','This resulted in...'],structure:['Set up the disagreement: who, what was at stake','State their position fairly (shows empathy)','State your position with evidence','How you navigated to resolution','Outcome + principle extracted'],sample_answer:'My VP wanted us to ship a feature by end of quarter, but the design had no rate limiting. I\'d argue that launching without the rate limiter is riskier than delaying by a week. If we get a traffic spike, we won\'t just be slow — we\'ll be down. That said, I understood the business pressure, so I proposed shipping the feature with a configurable rate limit that we could tighten after launch. We shipped on time. Two weeks later, a bot hit our API and the rate limiter saved us from an outage. The lesson I took away was that you can usually find a middle path if you acknowledge the other side\'s constraints.',pitfalls:['Don\'t paint the other person as wrong or unreasonable','Don\'t skip how you resolved it — the process matters more than who was right','Don\'t describe a trivial disagreement (code style preferences)']},{id:'influence-without-authority',text:'Tell me about a time you had to influence a decision without formal authority.',competency:'leadership',framework:'STAR-LA',patterns:['What I\'d really highlight is...','Building on that...','This resulted in...'],structure:['Context: what decision, who owned it, why you cared','Your approach: how you built the case (data, allies, prototypes)','The turning point: what convinced them','Impact of the decision','Learning about influence'],sample_answer:'The mobile team was about to build a separate authentication system. I owned the web platform and knew this would create two sources of truth for user identity. I didn\'t own the mobile team\'s roadmap. What I\'d really highlight is the approach: I didn\'t argue. I wrote a one-page RFC showing the security implications of two auth systems, built a prototype showing shared auth was faster to implement, and got the security team to review it. Building on that, the mobile team lead changed the plan voluntarily. This resulted in shipping 3 weeks earlier with a single auth system. The lesson I took away was that influence works through evidence and allies, not authority.',pitfalls:['Don\'t just say \'I convinced them\' — show the method','Don\'t skip who you allied with — influence is social','Don\'t describe a situation where you actually had authority']},{id:'failure',text:'Tell me about a project that didn\'t go as planned. What happened?',competency:'accountability',framework:'Hook-Flow-Landing',patterns:['What surprised me was...','The lesson I took away was...','Looking back, I would...'],structure:['Hook: start with the most surprising or dramatic moment','What went wrong: be specific, own your part','What you did to recover (if applicable)','Root cause analysis: what you learned','Systemic change: what you changed so it wouldn\'t happen again'],sample_answer:'We discovered we\'d been silently dropping transactions for two weeks. I was the engineer on call. A library upgrade had changed the error handling behavior, and our tests didn\'t cover that edge case. What surprised me was that our monitoring showed green the entire time — we were monitoring for errors, but the new behavior returned success codes with empty responses. We immediately rolled back and patched the library. The lesson I took away was that you can\'t just monitor for errors — you have to monitor for business-level correctness. I added end-to-end transaction count monitoring that would have caught this in minutes instead of weeks.',pitfalls:['Don\'t blame others or external factors entirely','Don\'t pick a \'failure\' that was actually a success in disguise','Don\'t skip what you changed systemically — individual learning isn\'t enough']},{id:'ambiguous-problem',text:'Tell me about a time you had to solve a problem that wasn\'t clearly defined.',competency:'ambiguity-navigation',framework:'STAR-LA',patterns:['The crux of it is...','The first thing I would do is...','This resulted in...'],structure:['How you recognized the ambiguity','How you defined the problem (reframed, asked questions, gathered data)','Your approach to solving the now-defined problem','Result with numbers','Principle for handling ambiguity'],sample_answer:'Our support team reported \'the app is slow\' but couldn\'t say which part, for which users, or when. The crux of it is that \'slow\' isn\'t a problem you can fix — it\'s a symptom. The first thing I would do is make it specific. I added latency percentiles to every API endpoint and broke them down by region, device type, and time of day. Within a day, the data showed p99 latency on one endpoint was 12 seconds, but only for Android users in Asia. It was a DNS resolution issue in our CDN config. This resulted in p99 dropping to 200ms for that segment. The lesson I took away was that ambiguity is solved by measurement, not by guessing.',pitfalls:['Don\'t jump to solving before defining — they want to see how you clarify','Don\'t describe a problem that was actually well-defined','Don\'t skip the measurement or framing step']},{id:'learned-fast',text:'Tell me about a time you had to learn something completely new, quickly.',competency:'learning-agility',framework:'STAR-LA',patterns:['Here\'s how I\'d ramp up on that...','What clicked for me was...','This resulted in...'],structure:['What you had to learn and why it was urgent','Your learning strategy (specific, not \'I read the docs\')','Milestone: how you knew you were productive','Impact: what you accomplished with the new knowledge','Generalizable learning method'],sample_answer:'I had two weeks to become productive in Rust for a performance-critical service rewrite. Here\'s how I\'d ramp up on that: I learn best by building. I took the existing Go service, rewrote the hottest path in Rust, and ran both side by side. What clicked for me was that Rust\'s ownership model isn\'t just safety theater — it forces you to think about data flow, which actually made the code faster because there were no hidden allocations. Within two weeks I had the hot path running 4x faster. This resulted in us adopting Rust for all new performance-critical paths. The lesson I took away was that the fastest way to learn a technology is to apply it to a real problem with a measurable outcome.',pitfalls:['Don\'t just say \'I\'m a fast learner\' — show the specific method','Don\'t describe learning something easy or trivial','Don\'t skip the timeline — they want to see how fast is fast']},{id:'conflicting-priorities',text:'Tell me about a time you had to manage conflicting priorities from different stakeholders.',competency:'stakeholder-management',framework:'STAR-LA',patterns:['The key thing to understand is...','The trade-off here is...','This resulted in...'],structure:['The competing priorities and who owned each','How you analyzed the trade-offs (framework, data)','How you communicated your decision','Outcome + how you managed the deprioritized stakeholder','Principle for prioritization'],sample_answer:'The product team wanted a new onboarding flow, the security team needed a mandatory access control migration, and the CEO wanted AI features demoed at a conference. The key thing to understand is that I couldn\'t do all three with the team we had. The trade-off here is: security is non-negotiable (compliance deadline), AI demo is time-boxed (conference date), onboarding can ship next quarter. I proposed: 60% on security migration (deadline), 30% on AI demo (reusable prototype), 10% onboarding design (no code yet). I explained this to each stakeholder individually, showing what they\'d get and when. This resulted in hitting the compliance deadline, a successful demo, and the onboarding shipped 6 weeks later. The lesson I took away was that stakeholders accept prioritization when they see a plan, not just a rejection.',pitfalls:['Don\'t say \'I did everything\' — that\'s not realistic','Don\'t avoid naming the trade-off explicitly','Don\'t skip how you communicated with the deprioritized stakeholder']},{id:'mentored-someone',text:'Tell me about someone you helped grow professionally.',competency:'developing-others',framework:'STAR-LA',patterns:['Over time I became the...','What I\'d really highlight is...','This resulted in...'],structure:['Who the person was and their starting point','Your mentoring approach (specific, not \'I gave advice\')','Their growth trajectory with evidence','Impact on the team/org','Your philosophy on developing others'],sample_answer:'A junior engineer on my team was great at coding but struggled with code review feedback — they\'d get defensive and push back on every suggestion. Over time I became the person they came to for review strategy. My approach: instead of coaching them on accepting feedback, I had them do a 2-week rotation as a reviewer. Seeing the other side clicked for them — they realized reviewers aren\'t attacking, they\'re protecting the codebase. What I\'d really highlight is that within 3 months, they went from the most contentious review participant to the most constructive. This resulted in the team\'s review turnaround dropping from 48 hours to 4 hours. The lesson I took away was that developing others sometimes means creating experiences, not just giving advice.',pitfalls:['Focus on the other person\'s growth, not your brilliance','Don\'t describe casual advice — show sustained effort','Don\'t skip measurable outcomes for the mentee']},{id:'raised-the-bar',text:'Tell me about a time you improved something that was already working.',competency:'high-standards',framework:'STAR-LA',patterns:['Before this... After this...','What I\'d really highlight is...','The lesson I took away was...'],structure:['What was working (acknowledge it wasn\'t broken)','Why you saw room for improvement','What you did differently and why','Measurable improvement with numbers','Principle about high standards'],sample_answer:'Our CI pipeline was working — builds completed in about 12 minutes. The team was fine with it. Before this... After this... Before, we ran all tests sequentially on a single machine. After, I parallelized the test suite across 8 runners and added incremental builds that only tested affected modules. Build time dropped from 12 minutes to 3 minutes. What I\'d really highlight is that the 9-minute saving per build added up to 2 hours per developer per week. The lesson I took away was that \'working\' is not the same as \'good enough to stop improving\' — especially for infrastructure that everyone uses daily.',pitfalls:['Don\'t describe something that was actually broken','Don\'t skip the before/after numbers','Don\'t improve something nobody cares about — pick high-leverage improvements']},{id:'build-vs-buy',text:'Tell me about a build-versus-buy decision you were involved in.',competency:'judgment',framework:'STAR-LA',patterns:['The way I see it is...','That said...','This resulted in...'],structure:['Context: what capability was needed and why','The build option: effort, timeline, customization','The buy option: cost, constraints, integration','How you evaluated (criteria, data, not just gut)','Decision and outcome with timeline'],sample_answer:'We needed a document editor for our product. The way I see it is, building gives us full control but takes 6+ months. That said, buying ProseMirror would give us 80% of what we need in 2 weeks, with the ability to customize the remaining 20%. I evaluated on 3 axes: time to market, customization depth, and maintenance cost. We bought ProseMirror and built custom plugins for our domain-specific features. This resulted in shipping in 3 weeks instead of 6 months, and the maintenance cost has been minimal because the open-source community handles the core. The lesson I took away was that build vs buy isn\'t binary — the best option is often \'buy the core, build the differentiation.\'',pitfalls:['Don\'t just pick one without showing the analysis','Don\'t describe a decision where there was obviously only one choice','Don\'t ignore maintenance cost in your evaluation']},{id:'bad-news',text:'Tell me about a time you had to deliver difficult feedback or bad news.',competency:'communication',framework:'Hook-Flow-Landing',patterns:['I\'m glad you asked that...','What I\'d really highlight is...','This resulted in...'],structure:['Context: what was the bad news and to whom','How you prepared (timing, setting, framing)','What you said (be specific about language)','How the recipient responded','Follow-up and outcome'],sample_answer:'I had to tell a senior engineer on my team that he wasn\'t being promoted this cycle. I\'m glad you asked that, because it\'s one of the hardest conversations I\'ve had. I prepared by writing down specific, behavioral feedback — not \'you\'re not ready\' but \'in the last 3 projects, the code reviews identified these patterns that indicate Staff-level behavior isn\'t consistently demonstrated yet.\' I framed it as \'here\'s exactly what needs to change, and here\'s my plan to help you get there.\' He was upset initially, but the specificity gave him something to work on. Six months later, he was promoted. What I\'d really highlight is that vague feedback is cruel — specific feedback is a gift, even when it hurts.',pitfalls:['Don\'t describe easy feedback (telling someone about a minor bug)','Don\'t be vague about what you said — quote yourself','Don\'t skip the follow-up — delivery isn\'t the end']},{id:'process-improvement',text:'Tell me about a process you changed that made your team more effective.',competency:'engineering-mindset',framework:'STAR-LA',patterns:['Before this... After this...','This resulted in...','The lesson I took away was...'],structure:['What was the existing process and its problems','How you identified the root cause (not just the symptom)','What you changed and why','Measurable improvement','How you got team buy-in'],sample_answer:'Our deployment process required 3 manual approval steps and took 45 minutes per deploy. Developers deployed once a week because it was so painful. Before this... After this... Before: 3 manual approvals, 45 minutes, weekly deploys. After: automated canary deploys with rollback triggers, 5 minutes, multiple deploys per day. This resulted in deployment frequency increasing 10x and rollback time dropping from 30 minutes to 90 seconds. The lesson I took away was that the best process improvements remove steps rather than add them, and the way to get buy-in is to make the new process so much easier that people switch voluntarily.',pitfalls:['Don\'t describe a trivial process change (changing a meeting time)','Don\'t skip the before/after numbers','Don\'t add process — describe removing or simplifying it']},{id:'cross-team',text:'Tell me about a time you had to coordinate work across multiple teams.',competency:'collaboration',framework:'STAR-LA',patterns:['The other piece was...','Building on that...','This resulted in...'],structure:['Context: what initiative, how many teams, what was at stake','The coordination challenge (dependencies, misalignment)','Your approach to alignment (documents, meetings, shared goals)','How you handled the hardest dependency','Outcome + what you learned about cross-team work'],sample_answer:'We were migrating from a monolith to microservices and needed to coordinate changes across the platform team, the payments team, and the mobile team. The other piece was that each team had different release schedules. I wrote a migration contract — a shared document specifying exactly what each team would change, in what order, and what the integration test would verify. Building on that, I set up a weekly 15-minute sync where each team reported their status against the contract. This resulted in the migration completing 2 weeks ahead of schedule with zero production incidents. The lesson I took away was that cross-team coordination works when the contract is explicit and the sync is lightweight.',pitfalls:['Don\'t describe a single-team project','Don\'t skip the hardest dependency','Don\'t say \'I just communicated a lot\' — show the structure']},{id:'technical-decision',text:'Tell me about a technical decision you made that turned out to be wrong.',competency:'self-awareness',framework:'Hook-Flow-Landing',patterns:['The lesson I took away was...','Looking back, I would...','This resulted in...'],structure:['The decision and your reasoning at the time','How you discovered it was wrong','What you did to fix it','The systemic change you made so it wouldn\'t recur','What you learned about decision-making'],sample_answer:'I chose MongoDB for our transactional system because the schema was evolving rapidly. Six months later, we had data consistency issues that were causing real customer impact. Looking back, I would have started with PostgreSQL and used JSON columns for the evolving parts — we\'d have gotten schema flexibility plus ACID guarantees. When I realized the mistake, I led the migration back to PostgreSQL. The lesson I took away was that \'schema flexibility\' is not worth sacrificing consistency for transactional data. I also added a decision template to our architecture review process that forces us to write down: what happens if we\'re wrong, and how hard is it to reverse?',pitfalls:['Don\'t pick a decision where you were actually right in hindsight','Don\'t skip the systemic change — individual learning isn\'t enough','Don\'t blame the technology — own your decision']},{id:'customer-impact',text:'Tell me about a time you went beyond the requirements to solve a real customer problem.',competency:'customer-focus',framework:'STAR-LA',patterns:['What clicked for me was...','To give you a concrete example...','This resulted in...'],structure:['The stated requirements vs the real customer need','How you discovered the deeper need','What you did beyond the spec','Customer reaction and measurable impact','Principle about customer-centricity'],sample_answer:'The product spec said \'add a CSV export button.\' What clicked for me was that the support tickets weren\'t about exporting — they were about spending 4 hours every Friday manually reformatting the exported data into their reporting format. To give you a concrete example: one customer exported 50K rows and then spent 3 hours in Excel doing vlookups. I built a customizable export template that let users define their own column mapping and filters. This resulted in a 95% reduction in support tickets about exports and the feature became the #2 reason for upgrades. The lesson I took away was that requirements describe symptoms — you have to understand the job the customer is trying to do.',pitfalls:['Don\'t describe gold-plating (adding features nobody asked for)','Don\'t skip how you discovered the real need','Don\'t ignore the spec entirely — show you addressed it AND went beyond']},{id:'scaling-challenge',text:'Tell me about a time you had to redesign something to handle significant growth.',competency:'systems-thinking',framework:'STAR-LA',patterns:['Before this... After this...','At our scale, we had to...','The trade-off here is...'],structure:['What was the system and how it was originally designed','The growth signal that triggered the redesign','Your analysis of the bottleneck','The new design and key decisions','Results at the new scale'],sample_answer:'Our notification service was a single Postgres instance with a polling model. Before this... After this... Before: single DB, 100 notifications/sec, 2-second latency. After: sharded Kafka + Redis with push model, 50K notifications/sec, 50ms latency. At our scale, we had to move from polling to pushing because the DB couldn\'t handle 10K concurrent polls. The trade-off here is between simplicity (polling) and efficiency (push with the complexity of WebSocket management). This resulted in handling 500x the traffic with lower latency. The lesson I took away was that scaling redesigns should be data-driven — we measured before we decided what to change.',pitfalls:['Don\'t describe premature optimization — show real growth pressure','Don\'t skip the bottleneck analysis','Don\'t forget to name the trade-offs in your new design']},{id:'security-incident',text:'Tell me about a time security requirements conflicted with delivery timelines.',competency:'risk-management',framework:'STAR-LA',patterns:['I\'d argue that...','The trade-off here is...','This resulted in...'],structure:['The security requirement and the delivery pressure','Your analysis of the risk (probabilistic, not absolute)','How you balanced the trade-off','The compromise or creative solution','Outcome and principle'],sample_answer:'Security required all API calls to use mTLS, but implementing it would delay our launch by 3 weeks. I\'d argue that the trade-off here is between perfect security and actual security. Shipping without any auth is dangerous, but a 3-week delay means 3 weeks with zero customers getting value. I proposed: ship with API key auth (sufficient for launch), add mTLS in the next sprint (2 weeks post-launch), and put all internal services behind a VPN in the meantime. This resulted in launching on time, zero security incidents during the 2-week window, and mTLS shipping 2 weeks later. The lesson I took away was that risk management is about reducing risk to acceptable levels, not eliminating it — and a shipped product with good-enough security beats an unshipped product with perfect security.',pitfalls:['Don\'t describe a situation where security was clearly non-negotiable (e.g., PCI compliance)','Don\'t dismiss security concerns — show you took them seriously','Don\'t skip the compromise — they want to see creative problem-solving']},{id:'automation',text:'Tell me about something you automated that had a big impact.',competency:'efficiency',framework:'STAR-LA',patterns:['To give you a concrete example...','Before this... After this...','This resulted in...'],structure:['What was manual and how painful it was','How you identified it as an automation target','What you built and the key design decisions','Before/after with numbers','How you got people to trust and use the automation'],sample_answer:'To give you a concrete example — one BA spent two days a week compiling data from five different systems into a single report. Before this... After this... Before: 16 hours/week of manual work, errors in 15% of reports, delivered Friday afternoon. After: automated pipeline runs in 30 minutes, zero errors, delivered Monday 6 AM. I built it as a scheduled Lambda that pulls from each system, transforms, and writes to a shared spreadsheet. This resulted in saving 800 person-hours/year and the BA moved to strategic analysis work. The lesson I took away was that the best automation targets are high-frequency, error-prone manual processes that trap smart people in repetitive work.',pitfalls:['Don\'t describe automating something trivial (a one-off script)','Don\'t skip the before/after numbers','Don\'t forget the trust angle — people don\'t use automation they don\'t trust']},{id:'team-disagreement',text:'Tell me about a time the team was split on a technical decision and how you resolved it.',competency:'conflict-resolution',framework:'STAR-LA',patterns:['I see it a bit differently...','The trade-off here is...','This resulted in...'],structure:['The decision and the two camps','Why each side had valid concerns','How you facilitated resolution (data, prototype, compromise)','The decision and how you got buy-in from the other side','Outcome and principle'],sample_answer:'Half the team wanted GraphQL and half wanted REST for our new API. I see it a bit differently — both have valid trade-offs. The trade-off here is flexibility vs simplicity. Instead of debating, I proposed: build a REST API for the 5 most common operations (covering 90% of traffic), and add a GraphQL endpoint for the complex query patterns that the mobile team needed. I built a prototype of both in a week and we measured: REST was 3x faster for simple queries, GraphQL was 2x better for complex ones. The data resolved the debate. This resulted in shipping both and the team moved on in a week instead of debating for a month. The lesson I took away was that data beats debate — and most technical disagreements have a \'both\' solution if you look for it.',pitfalls:['Don\'t describe a situation where one side was obviously wrong','Don\'t say \'I just decided\' — show the facilitation','Don\'t skip how you got the losing side to buy in']},{id:'why-this-company',text:'Why do you want to work here specifically?',competency:'motivation',framework:'Structure-First',patterns:['What I\'m really looking for is...','What clicked for me was...','Over time I became the...'],structure:['Specific technical or cultural attraction (not generic)','How it connects to your career trajectory','What you\'d contribute (not just what you\'d get)','Evidence you\'ve researched the company'],sample_answer:'What I\'m really looking for is a team where platform engineering is a first-class discipline, not an afterthought. What clicked for me was reading your engineering blog about the internal developer platform — the fact that you measure developer productivity as a first-class metric tells me you take platform work seriously. Over time I became the platform engineering advocate at my current company, and I want to join a place where I can learn from people who\'ve been doing it longer and at larger scale. Specifically, I\'d want to contribute to your deployment orchestration work — my experience with canary deployments would be directly applicable.',pitfalls:['Don\'t give a generic answer (\'great culture, smart people\')','Don\'t focus only on what you\'ll get — show what you\'ll contribute','Don\'t say things that could apply to any company']},{id:'design-url-shortener',text:'Design a URL shortener like Bitly.',competency:'system-design',framework:'RESHADED',patterns:['At a high level...','The trade-off here is...','The simpler approach would be...'],structure:['Requirements: short URL creation, redirect, analytics, high read ratio','Estimation: 100M URLs/day, 10:1 read:write, ~2TB storage','Storage: key-value store (short_code → long_url + metadata)','High-level: API server, KV store, cache, analytics pipeline','API: POST /shorten, GET /{code} → 301/302','Detail: ID generation — auto-increment + base62 vs random key','Trade-offs: 301 (cached, fast) vs 302 (trackable, slower)'],sample_answer:'At a high level, there are three components: the API layer, the storage layer, and the analytics pipeline. The trade-off here is between 301 and 302 redirects — 301 lets browsers cache, which is faster but means we can\'t track clicks. I\'d use 302 with a caching layer for the hot paths. For ID generation, the simpler approach would be to use a pre-generated pool of random keys stored in a database — this avoids coordination and we can generate them in batches offline. For storage, any KV store works — DynamoDB or Cassandra for scale. Cache the top 1% of URLs in Redis (the viral ones). Analytics go to a Kafka topic and get aggregated downstream.',pitfalls:['Don\'t skip estimation — they want to see you can reason about scale','Don\'t over-engineer the ID generation — start simple','Don\'t forget about the analytics requirement']},{id:'design-chat',text:'Design a real-time chat system like WhatsApp.',competency:'system-design',framework:'RESHADED',patterns:['At a high level...','The trade-off here is...','The failure mode I\'m most concerned about is...'],structure:['Requirements: 1:1 and group chat, online status, message history','Estimation: 50M DAU, 10K msg/s peak','Storage: message table partitioned by conversation_id','High-level: WebSocket servers, message queue, presence service','Detail: fan-out on write vs read for group chats','Trade-offs: WebSocket vs long polling, ordering guarantees'],sample_answer:'At a high level, we have connection handlers, a message routing layer, and storage. The trade-off here is fan-out strategy: for 1:1 chat, write to both users\' inboxes. For group chat with <50 members, fan-out on write. For larger groups, fan-out on read. The failure mode I\'m most concerned about is message ordering — if two messages arrive at different servers simultaneously, we need to preserve order within a conversation. I\'d use per-conversation sequence numbers generated by a single partition owner. For presence, use heartbeats with TTL in Redis — simpler than a dedicated presence service.',pitfalls:['Don\'t forget offline message delivery','Don\'t ignore the group chat fan-out problem','Don\'t skip message ordering guarantees']},{id:'design-feed',text:'Design a social news feed like Twitter.',competency:'system-design',framework:'RESHADED',patterns:['At a high level...','The trade-off here is...','If we zoom out for a moment...'],structure:['Requirements: personalized feed, ranking, pagination, real-time','Estimation: 100M DAU, 500M posts/day, avg 200 follows','Storage: post table, follow table, pre-computed feed table','Detail: hybrid fan-out (write for normal, read for celebrities)','Trade-offs: chronological vs ML ranking, pagination strategy'],sample_answer:'If we zoom out for a moment, the core problem is: given a user, return the N most relevant posts from people they follow, fast. The trade-off here is fan-out cost vs feed generation latency. I\'d use a hybrid: when a normal user posts, push to all followers\' pre-computed feeds (fan-out on write). When a celebrity posts, don\'t push — instead, merge their posts at read time. This gives O(1) feed reads for most users and O(celebrity_count) for celebrity followers. For ranking, start chronological and add ML ranking later. Use cursor-based pagination, not offset — new posts arriving during scroll would break offset-based pagination.',pitfalls:['Don\'t ignore the celebrity problem (millions of followers)','Don\'t use offset pagination — it breaks with new posts','Don\'t skip the ranking discussion']},{id:'design-search',text:'Design a search autocomplete system.',competency:'system-design',framework:'RESHADED',patterns:['The first thing I would do is...','At a high level...','The simpler approach would be...'],structure:['Requirements: suggest as user types, <50ms latency, top 5','Estimation: 100M queries/day, top 5 per prefix','Storage: trie or N-gram with top-K completions per prefix','Detail: ranking by frequency + personalization + freshness','Trade-offs: trie size, update latency, personalization cost'],sample_answer:'The first thing I would do is clarify: are we suggesting queries or documents? Assuming queries. At a high level, we need a prefix index and a ranking function. The simpler approach would be to store top-K completions for each prefix — precompute the top 5 for every prefix up to length N. This uses more memory but gives O(1) lookup. For a query like \'how t\', we look up the key \'how t\' and return the precomputed list. Updates happen by incrementing a counter and periodically recomputing top-K. For trending queries, we can boost their score with a time-decay function. Shard by prefix first character for horizontal scaling.',pitfalls:['Don\'t propose building a full trie traversal at query time — too slow','Don\'t forget about trending/fresh queries','Don\'t skip how you handle the cold-start problem for new prefixes']},{id:'design-storage',text:'Design an object storage system like S3.',competency:'system-design',framework:'RESHADED',patterns:['The trade-off here is...','The failure mode I\'m most concerned about is...','We can mitigate that by...'],structure:['Requirements: unlimited objects, 99.999999999% durability, 99.99% availability','Estimation: 100B objects, 1TB/day ingestion','Storage: erasure coding across nodes and zones','Detail: metadata service, data placement, garbage collection','Trade-offs: erasure coding vs replication, consistency model'],sample_answer:'The trade-off here is between replication and erasure coding. Erasure coding gives 11 nines durability with 1.4x storage overhead vs 3x for triple replication. I\'d use erasure coding within a region (Reed-Solomon 8+4) and cross-region replication for disaster recovery. The failure mode I\'m most concerned about is the metadata service becoming a bottleneck — every read and write hits it. We can mitigate that by partitioning metadata by object key prefix and caching hot metadata. For consistency: read-after-write for new objects (synchronous replication to quorum), eventual consistency for overwrites (async propagation). Garbage collection runs as a background sweep that reconciles reference counts.',pitfalls:['Don\'t propose full replication — too expensive at S3 scale','Don\'t forget about the metadata bottleneck','Don\'t skip the garbage collection / orphan cleanup problem']},{id:'design-notification',text:'Design a notification system supporting push, SMS, and email.',competency:'system-design',framework:'RESHADED',patterns:['At a high level...','The simpler approach would be...','We can mitigate that by...'],structure:['Requirements: 3 channels, templates, preferences, delivery tracking','Estimation: 10M notifications/day, 100ms send latency','Storage: notification table, template store, preference store','Detail: priority queues, rate limiting, retry logic','Trade-offs: per-channel vs unified queue, retry vs idempotency'],sample_answer:'At a high level, there are four components: the API, the router, the channel workers, and the preference store. The simpler approach would be a single priority queue per channel — push workers read from the push queue, SMS from the SMS queue. Rate limiting uses a token bucket per user per channel, stored in Redis. We can mitigate double-sending by using idempotency keys — each notification gets a unique ID, and channel workers check if they\'ve already sent it. For templates, store them in a document store and render at send time with user-specific variables. Track delivery status via callbacks from the channel providers (APNs delivery receipts, SNS delivery logs, SES bounce/complaint notifications).',pitfalls:['Don\'t forget rate limiting — notification fatigue is real','Don\'t skip the preference/opt-out system','Don\'t ignore retry logic — but make it idempotent']},{id:'design-crawler',text:'Design a distributed web crawler.',competency:'system-design',framework:'RESHADED',patterns:['The first thing I would do is...','The trade-off here is...','The failure mode I\'m most concerned about is...'],structure:['Requirements: discover, download, process, index billions of pages','Estimation: 10B pages, 1PB raw, 100 pages/s per node','Storage: URL frontier, raw HTML in object store, metadata in DB','Detail: deduplication, politeness, scheduling, distribution','Trade-offs: breadth vs depth, freshness vs coverage, politeness vs speed'],sample_answer:'The first thing I would do is define what we\'re crawling and how often. The trade-off here is breadth vs depth — do we crawl everything once, or focus on important sites frequently? I\'d use a priority queue as the URL frontier, where priority is based on page importance and freshness requirements. Deduplication uses a Bloom filter — O(1) check for \'have we seen this URL?\' with a small false positive rate. The failure mode I\'m most concerned about is being impolite — hammering a small site with 100 requests/second. We mitigate with per-domain rate limiting: maintain a mapping of domain → last_crawl_time + min_interval. Distribute by partitioning the URL frontier by domain hash, so all URLs for one domain go to the same crawler node.',pitfalls:['Don\'t forget the robots.txt / politeness requirement','Don\'t skip URL deduplication at scale','Don\'t ignore the freshness problem — when to re-crawl?']},{id:'design-kv-store',text:'Design a distributed key-value store.',competency:'system-design',framework:'RESHADED',patterns:['At a high level...','The trade-off here is...','Under normal conditions... Under edge cases...'],structure:['Requirements: get/put/delete, highly available, low latency, tunable consistency','Estimation: 1TB data, 1M reads/s, 100K writes/s','Storage: consistent hashing, replication factor N','Detail: quorum reads/writes, vector clocks, read repair','Trade-offs: consistency level per operation, R+W>N guarantee'],sample_answer:'At a high level, data is partitioned across nodes using consistent hashing with virtual nodes, and each key is replicated to N nodes. The trade-off here is consistency vs latency — we let the client choose. For reads, specify R (how many replicas to read from). For writes, specify W (how many to acknowledge). If R+W>N, you get strong consistency. Under normal conditions, a write goes to the coordinator node, which sends it to all N replicas and waits for W acknowledgments. Under edge cases — a network partition — if W nodes are available, the write succeeds but some replicas are stale. We handle this with read repair: when a read hits multiple replicas with different versions, we reconcile using vector clocks and write the merged version back. Anti-entropy uses Merkle trees to efficiently compare replica states.',pitfalls:['Don\'t skip the quorum read/write explanation','Don\'t forget conflict resolution (vector clocks or CRDTs)','Don\'t ignore the hot key / celebrity problem']},{id:'design-location',text:'Design a location-based service like Uber.',competency:'system-design',framework:'RESHADED',patterns:['At a high level...','The first thing I would do is...','The trade-off here is...'],structure:['Requirements: find nearby drivers, real-time location updates, ETA','Estimation: 10M active users, updates every 5s, 1M queries/s','Storage: spatial index (geohash/quadtree/S2), driver location cache','Detail: geohashing, proximity search, location update pipeline','Trade-offs: index resolution vs query precision, update frequency vs write load'],sample_answer:'At a high level, we need to store driver locations and query for nearby drivers within a radius. The first thing I would do is choose a spatial indexing strategy. I\'d use geohashing: encode lat/lng into a string where nearby locations share prefixes. To find drivers within 2km, compute the geohashes covering that area and query all matching cells. The trade-off here is resolution vs write load: 12-character geohashes give ~3cm precision but create many cells. I\'d use 6-character (1.2km × 0.6km) and search the 9 surrounding cells for a 2km radius. Driver locations update every 5 seconds via a WebSocket connection. Store active driver locations in Redis (geohash → set of driver IDs) and use the GEOADD/GEORADIUS commands which handle this natively. For ETA estimation, call a routing API with the driver and rider coordinates.',pitfalls:['Don\'t propose scanning all drivers — that\'s O(n)','Don\'t forget the write load from frequent location updates','Don\'t skip how you handle sparse vs dense areas']},{id:'design-streaming',text:'Design a video streaming platform like YouTube.',competency:'system-design',framework:'RESHADED',patterns:['At a high level...','The trade-off here is...','We can mitigate that by...'],structure:['Requirements: upload, transcode, stream, recommend, analytics','Estimation: 500M hours/day, 500 hours uploaded/minute','Storage: object storage for video, CDN for delivery, metadata DB','Detail: upload flow, transcoding pipeline, CDN strategy, recommendations','Trade-offs: transcoding latency vs quality, CDN cost vs coverage'],sample_answer:'At a high level, the pipeline is: upload → transcode → store → serve via CDN → recommend → track analytics. The trade-off here is between transcoding time and quality options. I\'d transcode to 4 resolutions (1080p, 720p, 480p, 360p) using a distributed worker pool. Uploads go to object storage via presigned URLs — the client uploads directly, no bottleneck through our servers. CDN strategy: push popular content to edge locations, pull everything else on first view. We can mitigate the cold-start problem by proactively pushing newly uploaded videos from popular creators to edge nodes. For recommendations, use collaborative filtering pre-computed offline, served from a cache layer. Analytics events stream to a data warehouse via Kafka for both reporting and ML model retraining.',pitfalls:['Don\'t forget adaptive bitrate streaming (HLS/DASH)','Don\'t skip the transcoding pipeline — it\'s the most expensive part','Don\'t ignore live streaming if relevant — very different from VOD']},{id:'handle-production-outage',text:'Walk me through how you\'d handle a production outage.',competency:'incident-management',framework:'Structured approach',patterns:['The first thing I would do is...','At a high level...','This resulted in...'],structure:['Acknowledge and communicate (don\'t debug silently)','Mitigate first, root-cause later (reduce blast radius)','Form hypothesis and investigate systematically','Communicate status updates regularly','Post-mortem: root cause, timeline, action items'],sample_answer:'The first thing I would do is acknowledge the incident and page the on-call team. At a high level, my priority order is: 1) Mitigate — can we roll back, failover, or feature-flag off the affected path? 2) Communicate — post an incident status with what we know, even if it\'s just \'we\'re aware and investigating.\' 3) Investigate — check the most likely causes first: recent deployments, downstream dependencies, infrastructure changes. I use a binary search approach: eliminate halves of the system until I find the failing component. After resolution, I write a post-mortem with: timeline, root cause, 5 Whys analysis, and specific action items with owners. This resulted in a culture where post-mortems are blameless and action items are tracked in the sprint.',pitfalls:['Don\'t start debugging before mitigating — reduce blast radius first','Don\'t work alone — communicate early and often','Don\'t skip the post-mortem — the real value is preventing recurrence']},{id:'debug-latency-spike',text:'How would you debug a sudden latency spike in your service?',competency:'debugging',framework:'Structured approach',patterns:['The first thing I would do is...','The crux of it is...','We can mitigate that by...'],structure:['Check dashboards: p50/p90/p99, error rate, throughput','Correlate with recent changes (deployments, config, load)','Narrow down: which endpoints, which users, which region','Check infrastructure: CPU, memory, disk, network','Check dependencies: downstream latency, cache hit rates, DB slow queries'],sample_answer:'The first thing I would do is look at the metrics dashboard to narrow the scope. Is it all endpoints or one? All regions or one? When did it start? Then I check: was there a recent deployment? A config change? A scheduled job running? If nothing obvious, the crux of it is usually one of three things: a slow downstream dependency (check circuit breaker logs), a cache miss spike (check cache hit rates and eviction rates), or a database problem (check slow query logs, connection pool usage, replication lag). I approach it systematically: eliminate possibilities starting with the most likely. Once I find the cause, I mitigate first (scale up, add caching, disable the slow feature) and then fix the root cause.',pitfalls:['Don\'t guess — start with data and eliminate possibilities','Don\'t forget to check downstream services, not just your own','Don\'t skip the correlation with recent changes']},{id:'manage-technical-debt',text:'How do you manage technical debt in a fast-moving team?',competency:'engineering-craft',framework:'Structured approach',patterns:['My approach to [X] is...','The trade-off here is...','This resulted in...'],structure:['Categorize: risk debt (security, reliability) vs friction debt (slow dev) vs design debt (wrong abstractions)','Prioritize: risk debt first, then friction that slows daily work','Allocate: 20% of sprint capacity consistently','Make it visible: track debt items in backlog with estimated cost','Prevent: code review standards, architecture decision records'],sample_answer:'My approach to technical debt is to treat it like credit card debt — it\'s fine to carry a balance, but you need a paydown plan and you need to understand the interest rate. The trade-off here is between shipping now and paying later. I categorize debt into three buckets: risk debt (it might break — security vulnerabilities, missing tests for critical paths), friction debt (it slows us down — slow builds, flaky tests, manual deployments), and design debt (it\'s hard to change — wrong abstractions, tight coupling). Risk debt gets fixed immediately. Friction debt gets 20% of every sprint. Design debt gets addressed during feature work that touches that code. This resulted in our build time going from 12 minutes to 3 minutes and our deployment frequency increasing 10x over 6 months.',pitfalls:['Don\'t say \'I don\'t let technical debt accumulate\' — unrealistic','Don\'t ignore the difference between risk debt and convenience debt','Don\'t skip how you make debt visible to stakeholders']},{id:'deal-with-legacy-code',text:'Tell me about a time you had to work with a difficult legacy codebase.',competency:'adaptability',framework:'STAR-LA',patterns:['The first thing I would do is...','Before this... After this...','Looking back, I would...'],structure:['How you approached understanding the codebase','What made it difficult (technical and social)','Your strategy for making changes safely','Impact of your work','What you learned about working with legacy systems'],sample_answer:'I inherited a 10-year-old Java service with no tests, no documentation, and the original authors had left. The first thing I would do is characterize the risk: which parts are stable (don\'t touch) and which are fragile (need tests before changes). I added characterization tests — tests that capture current behavior, even if it\'s buggy — for the critical paths. Then I used the strangler fig pattern: built new features as separate services that called the legacy system, gradually routing traffic away. Before this... After this... Before, every change took 2 weeks and broke something. After, new features shipped in days without touching the legacy code. Looking back, I would have started with better observability — you can\'t safely change what you can\'t see.',pitfalls:['Don\'t describe a rewrite — they want to see incremental approach','Don\'t bash the legacy code or its authors','Don\'t skip the testing strategy — that\'s how you change safely']},{id:'on-call-experience',text:'Tell me about your most challenging on-call experience.',competency:'reliability',framework:'Hook-Flow-Landing',patterns:['What surprised me was...','This resulted in...','The lesson I took away was...'],structure:['Hook: the alert and initial severity','Your immediate actions (triage, communication)','The investigation and resolution','Systemic improvements you drove afterward','What you learned about operational excellence'],sample_answer:'I got paged at 3 AM: error rate on the payment service went from 0.1% to 40%. What surprised me was that the dashboard showed the problem started 2 hours before the alert triggered — our alerting threshold was too high. I immediately checked for recent deployments — one had gone out 3 hours before. I rolled back and the error rate dropped to normal within 5 minutes. This resulted in three systemic changes: 1) lowered the alerting threshold to catch degradation earlier, 2) added automatic rollback triggers that revert a deployment if error rate exceeds 5% within the first 30 minutes, 3) added a deployment checklist that requires monitoring the service for 30 minutes post-deploy. The lesson I took away was that every incident is a systems problem, not a people problem — if an incident can happen, the system should prevent it or detect it faster.',pitfalls:['Don\'t describe a trivial page (disk space warning)','Don\'t skip the systemic improvements — they want to see you prevent recurrence','Don\'t work alone in the story — show communication']},{id:'code-review-philosophy',text:'What\'s your philosophy on code reviews?',competency:'engineering-craft',framework:'Structure-First',patterns:['My approach to [X] is...','The key thing to understand is...','This resulted in...'],structure:['Core principle (teaching vs gatekeeping, speed vs thoroughness)','How you prioritize review comments (blocking vs suggestions)','How you handle disagreements','How you ensure timely reviews','Measurable impact of your approach'],sample_answer:'My approach to code review is to understand the intent before evaluating the implementation. The key thing to understand is that a code review is a conversation, not an exam. I categorize my comments into three types: blocking (must fix — bugs, security, breaking changes), important (should fix — performance, readability), and suggestions (optional — style, alternative approaches). Blocking comments prevent merge. Everything else is a discussion. I aim to review within 4 hours — stale reviews waste everyone\'s time. This resulted in our team\'s review turnaround dropping from 2 days to 4 hours, and developer satisfaction with the review process going from 3/5 to 4.5/5 in surveys. The lesson I took away was that review speed matters more than review thoroughness — a fast review with 80% coverage beats a slow review with 100%.',pitfalls:['Don\'t be a gatekeeper — show you enable, not block','Don\'t skip how you handle disagreements in reviews','Don\'t ignore the speed aspect — slow reviews kill productivity']},{id:'prioritize-features',text:'How do you prioritize features when everything seems important?',competency:'prioritization',framework:'Structure-First',patterns:['The key thing to understand is...','The trade-off here is...','This resulted in...'],structure:['Your prioritization framework (impact/effort, RICE, etc.)','How you gather data (customer signals, metrics, stakeholder input)','How you communicate priorities (roadmap, backlog ranking)','How you handle pushback from stakeholders','Example of a specific prioritization decision'],sample_answer:'The key thing to understand is that everything is not equally important — stakeholders just have different perspectives on what matters most. The trade-off here is between being data-driven and being responsive to emerging needs. I use a simple framework: score each feature on customer impact (1-5), engineering effort (1-5), and strategic alignment (1-5). Customer impact is weighted 2x because building something nobody uses is the biggest waste. I also look at leading signals: support tickets, feature requests, usage analytics, competitive pressure. When stakeholders push back, I don\'t say no — I say \'yes, and here\'s where it fits in the queue.\' This resulted in shipping the 3 features with the highest customer impact first, and they drove 40% more engagement than the features stakeholders originally prioritized.',pitfalls:['Don\'t say \'I just do what the PM says\' or \'I just pick the most interesting one\'','Don\'t skip how you handle stakeholder pushback','Don\'t ignore customer signals — that\'s the whole point']},{id:'convince-team-change',text:'Tell me about a time you had to convince your team to change direction.',competency:'influence',framework:'STAR-LA + Acknowledge-Reframe',patterns:['I\'d argue that...','That said...','This resulted in...'],structure:['Context: what was the current direction and why change was needed','How you built the case (data, prototype, external evidence)','How you acknowledged the cost of changing','The turning point: what convinced the team','Outcome and what you learned about influence'],sample_answer:'The team was building a custom ORM because we thought it would be faster than adopting an existing one. I\'d argue that maintaining a custom ORM will cost us 2+ hours per week per developer in bug fixes and feature additions, based on the commit history from the last 3 months. That said, I understand the hesitation — the existing ORMs don\'t handle our multi-tenant schema well. So I built a prototype showing that TypeORM with a custom decorator could handle our multi-tenant pattern in 50 lines of code. The turning point was when the most skeptical engineer reviewed the prototype and said \'this is actually cleaner than what we have.\' This resulted in migrating in 2 weeks and saving 10+ hours/week of maintenance. The lesson I took away was that the best way to convince engineers is with code, not arguments.',pitfalls:['Don\'t describe a situation where you had authority to just decide','Don\'t skip the data or evidence — opinions don\'t convince','Don\'t ignore the team\'s concerns — address them directly']}],sd_concepts:[{id:'cap-theorem',name:'CAP Theorem',category:'fundamentals',description:'In a distributed system, you can only guarantee two of: Consistency, Availability, and Partition tolerance. Since partitions are inevitable in distributed systems, the real choice is between consistency and availability during a partition.',key_points:['CP systems (e.g., ZooKeeper, etcd): Consistent but may refuse requests during partition','AP systems (e.g., Cassandra, DynamoDB): Available but may return stale data during partition','Most real systems are not strictly CP or AP — they offer tunable consistency','The theorem applies during network partitions, not under normal operation'],trade_offs:'Consistency vs Availability. Choose CP for financial transactions, AP for social media feeds.',real_examples:'DynamoDB: tunable consistency per request. MongoDB: eventually consistent by default, strongly consistent on reads with readConcern \'majority\'.'},{id:'acid-vs-base',name:'ACID vs BASE',category:'fundamentals',description:'ACID (Atomicity, Consistency, Isolation, Durability) guarantees strong consistency for transactional workloads. BASE (Basically Available, Soft state, Eventually consistent) trades consistency for availability and performance.',key_points:['ACID: database guarantees transactions are all-or-nothing, isolated from each other, and durable','BASE: accepts temporary inconsistency for better availability and partition tolerance','Most systems use both: ACID for critical paths (payments, account balances), BASE for everything else','The choice depends on business requirements, not technical preference'],trade_offs:'Strong consistency vs availability and performance. Use ACID when business rules require it, BASE when eventual consistency is acceptable.',real_examples:'Bank transfer: ACID (money must not disappear). Social feed: BASE (seeing a post 5 seconds late is fine).'},{id:'load-balancing',name:'Load Balancing',category:'infrastructure',description:'Distributes incoming traffic across multiple servers to improve availability, reliability, and performance. Essential for any system that needs to handle more traffic than a single server can support.',key_points:['Layer 4 (transport): load balances based on IP and port — fast, no packet inspection','Layer 7 (application): load balances based on HTTP headers, cookies, URL — smarter, can route by content','Algorithms: round-robin, least connections, weighted, consistent hashing','Health checks: remove unhealthy servers from the pool automatically','Session affinity: route same user to same server for stateful applications'],trade_offs:'Layer 4 is faster but less flexible. Layer 7 is smarter but adds latency. Session affinity simplifies state but limits scalability.',real_examples:'NGINX as L7 reverse proxy. AWS ALB for HTTP/HTTPS. HAProxy for both L4 and L7. Envoy for service mesh sidecar.'},{id:'caching',name:'Caching Strategies',category:'infrastructure',description:'Store frequently accessed data in a fast-access layer to reduce latency and database load. The single most impactful performance optimization in most systems.',key_points:['Cache-aside: application checks cache first, on miss loads from DB and writes to cache','Read-through: cache layer automatically loads from DB on miss','Write-through: write goes to cache and DB simultaneously','Write-behind: write goes to cache first, asynchronously flushed to DB','Eviction policies: LRU (least recently used), LFU (least frequently used), TTL (time to live)'],trade_offs:'Write-through: consistent but slower writes. Write-behind: faster writes but risk of data loss on failure. Cache-aside: most flexible but more application code.',real_examples:'Redis for cache-aside. Memcached for read-heavy workloads. CDN (CloudFront, Fastly) for static assets. Browser cache for client-side.'},{id:'database-sharding',name:'Database Sharding',category:'data',description:'Horizontally partition data across multiple database instances to handle datasets too large for a single machine. Each shard holds a subset of the data.',key_points:['Hash-based sharding: hash a key (e.g., user_id) to determine shard — even distribution but hard to reshard','Range-based sharding: assign key ranges to shards — supports range queries but may create hotspots','Directory-based sharding: lookup table maps keys to shards — flexible but lookup table is a bottleneck','Cross-shard queries: avoid them — they defeat the purpose of sharding','Resharding: the hardest operational problem — requires moving data without downtime'],trade_offs:'Hash sharding: even distribution but expensive resharding. Range sharding: efficient range queries but potential hotspots. Directory: flexible but adds latency and complexity.',real_examples:'Instagram: sharded by user_id with hash. MongoDB: built-in range-based sharding. Citus (Postgres extension): hash and range sharding.'},{id:'replication',name:'Database Replication',category:'data',description:'Copy data across multiple servers for redundancy, availability, and read scalability. The foundation of high-availability database architectures.',key_points:['Single-leader: one write node, multiple read replicas — simple, strongly consistent','Multi-leader: multiple write nodes — higher write availability, conflict resolution needed','Leaderless: any node can accept writes — highest availability, eventual consistency','Replication lag: async replicas may be behind the leader — stale reads are possible','Read-after-write consistency: ensure user reads their own writes, even with replication'],trade_offs:'Single-leader: simple but write bottleneck. Multi-leader: higher write throughput but conflict resolution. Leaderless: highest availability but complex consistency.',real_examples:'PostgreSQL streaming replication (single-leader). MySQL Group Replication (multi-leader). Cassandra and DynamoDB (leaderless).'},{id:'message-queues',name:'Message Queues & Event Streaming',category:'infrastructure',description:'Decouple producers from consumers by introducing an asynchronous communication layer. Essential for building resilient, scalable distributed systems.',key_points:['Point-to-point (queue): one consumer per message — task distribution','Publish-subscribe (topic): multiple consumers per message — event broadcasting','At-most-once: message may be lost — fastest, lowest guarantee','At-least-once: message is never lost but may be duplicated — requires idempotent consumers','Exactly-once: message processed once — hardest to achieve, often simulated via idempotency','Ordering: FIFO within a partition, no guaranteed cross-partition order'],trade_offs:'Throughput vs ordering. Exactly-once vs performance. Partition count limits parallelism but increases ordering guarantees.',real_examples:'RabbitMQ: point-to-point, at-least-once. Apache Kafka: partitioned log, high throughput, event sourcing. AWS SQS: managed queue, at-least-once. AWS SNS: managed pub-sub.'},{id:'cdn',name:'Content Delivery Network (CDN)',category:'infrastructure',description:'Distribute content from servers close to users to reduce latency. Fundamental for any global-scale web application.',key_points:['Push CDN: content uploaded to CDN in advance — for assets that change infrequently','Pull CDN: CDN fetches from origin on first request and caches — for dynamic content','Cache invalidation: the hardest problem — time-based TTL vs explicit purge','Edge compute: run logic at CDN edge (Cloudflare Workers, Lambda@Edge) — reduce round trips','Static vs dynamic: static assets (images, JS, CSS) are easy to cache; dynamic content needs careful cache headers'],trade_offs:'Push: full control but must manage uploads. Pull: automatic but first request is slow. Edge compute: lower latency but limited runtime environment.',real_examples:'CloudFront (AWS), Fastly, Cloudflare, Akamai. Static assets on CDN with 1-year cache. API responses with short TTL and stale-while-revalidate.'},{id:'microservices',name:'Microservices Architecture',category:'architecture',description:'Decompose a monolith into independently deployable services, each owning a business capability. The dominant architecture for large-scale systems — but comes with significant complexity costs.',key_points:['Service boundary: each service owns its data and exposes an API — no shared databases','Service discovery: services find each other dynamically (Consul, Kubernetes DNS, Eureka)','API gateway: single entry point for clients, handles routing, auth, rate limiting','Circuit breaker: stop cascading failures by failing fast when a downstream is unhealthy','Saga pattern: distributed transactions across services — orchestration vs choreography','Observability: distributed tracing (Jaeger, Zipkin), centralized logging, metrics per service'],trade_offs:'Independence vs coordination overhead. Easier to scale individual services but harder to debug cross-service issues. Team autonomy vs system coherence.',real_examples:'Netflix: pioneered microservices at scale. Amazon: two-pizza teams, each owning a service. Uber: domain-driven microservices with API gateway. Stripe: macro-service architecture (bigger services, fewer of them).'},{id:'consensus',name:'Consensus Protocols',category:'fundamentals',description:'How distributed nodes agree on a value despite failures. The foundation of leader election, distributed locking, and replicated state machines.',key_points:['Paxos: the theoretical gold standard — correct but notoriously hard to implement','Raft: designed to be understandable — leader election + log replication, used by etcd and CockroachDB','Byzantine Fault Tolerance: handles malicious nodes, not just crashed ones — used in blockchain','Quorum: majority agreement — N/2 + 1 nodes must agree for a decision','Leader election: one node coordinates, others follow — simplifies consensus but creates a single point of failure during election'],trade_offs:'Stronger consensus requires more network round trips. BFT is more resilient but much slower. Larger quorums are safer but reduce availability.',real_examples:'etcd and Consul use Raft. ZooKeeper uses a Paxos variant. Bitcoin uses Nakamoto consensus (proof-of-work).'},{id:'idempotency',name:'Idempotency',category:'reliability',description:'An operation is idempotent if executing it multiple times has the same effect as executing it once. Critical for building reliable distributed systems where retries are inevitable.',key_points:['Idempotency key: client sends a unique key with each request — server checks if already processed','Natural idempotency: PUT (replace), DELETE (same result), increment by fixed amount','Not naturally idempotent: POST (create), increment by 1, append to list','Database constraint: unique constraint on idempotency key prevents duplicate processing','Deduplication: store processed keys with TTL, reject duplicates within the window'],trade_offs:'Idempotency checks add latency and storage overhead. But without them, retries cause double-charges, duplicate messages, and inconsistent state.',real_examples:'Stripe: every API call requires an Idempotency-Key header. AWS SQS: exactly-once processing via deduplication IDs. HTTP: PUT and DELETE are idempotent by specification.'},{id:'rate-limiting',name:'Rate Limiting & Throttling',category:'reliability',description:'Control the rate of requests to protect services from being overwhelmed. Essential for public APIs, multi-tenant systems, and any service with resource constraints.',key_points:['Token bucket: tokens replenish at fixed rate, each request consumes one — allows burst up to bucket size','Leaky bucket: requests processed at fixed rate, excess queued or rejected — smooths traffic','Sliding window: count requests in a rolling time window — most accurate but more memory','Distributed rate limiting: use Redis with atomic operations or a dedicated service','Rate limit headers: X-RateLimit-Limit, X-RateLimit-Remaining, X-RateLimit-Reset'],trade_offs:'Token bucket: allows controlled bursts. Leaky bucket: strictly smooth. Sliding window: accurate but expensive. Per-user vs global limits: finer control vs simpler implementation.',real_examples:'Stripe: 100 requests per second per user. GitHub: 5000 requests per hour for authenticated users. Cloudflare: token bucket per IP at the edge.'},{id:'observability',name:'Observability (Metrics, Logs, Traces)',category:'reliability',description:'The ability to understand the internal state of a system from its external outputs. Not just monitoring — asking questions you didn\'t think to ask in advance.',key_points:['Metrics: numeric time-series data — request rate, error rate, latency percentiles (RED method)','Logs: discrete events with context — structured JSON logs with request ID, user ID, timestamp','Traces: end-to-end request flow across services — each span is a unit of work','Correlation IDs: unique ID attached to a request and propagated across all services','Alerting: define SLOs (e.g., p99 latency < 200ms) and alert on burn rate, not raw thresholds'],trade_offs:'Metrics: cheap to store, good for dashboards, limited context. Logs: rich context but expensive to store and search. Traces: full picture but high cardinality and sampling needed.',real_examples:'Prometheus + Grafana for metrics. ELK stack for logs. Jaeger/Zipkin for traces. Datadog for all three. OpenTelemetry as the standard instrumentation layer.'},{id:'data-partitioning',name:'Data Partitioning & Consistent Hashing',category:'data',description:'Distribute data across nodes so that adding or removing nodes minimizes data movement. The algorithm that makes distributed caches and databases scalable.',key_points:['Consistent hashing: place nodes and keys on a ring, each key belongs to the nearest clockwise node','Virtual nodes: each physical node maps to multiple points on the ring — smoother distribution','When a node joins: only keys between it and its predecessor need to move','When a node leaves: its keys move to the next node clockwise','Advantage: adding/removing nodes only affects K/N keys (K=total keys, N=total nodes)'],trade_offs:'Consistent hashing: minimal redistribution but may create hotspots. Virtual nodes: more even distribution but more complex. Range partitioning: efficient range queries but hotspot risk.',real_examples:'DynamoDB: consistent hashing with virtual nodes. Cassandra: token ring with virtual nodes. Riak: consistent hashing inspired by Amazon Dynamo.'},{id:'api-design',name:'API Design & Versioning',category:'architecture',description:'How to design APIs that are usable, evolvable, and backward-compatible. The contract between your service and its consumers.',key_points:['REST: resource-oriented, HTTP verbs, stateless — simple, widely understood','gRPC: protocol buffers, binary, bidirectional streaming — high performance, code generation','GraphQL: client specifies exact data shape — flexible, no over/under-fetching','Versioning strategies: URL path (/v1/), header (Accept: application/vnd.api.v1+json), query param (?v=1)','Backward compatibility: add fields as optional, never remove or rename — consumers should ignore unknown fields'],trade_offs:'REST: simple but may need many round trips. gRPC: fast but harder to debug and browser support is limited. GraphQL: flexible but complex server-side and N+1 query risk.',real_examples:'Stripe: REST with versioning via Stripe-Version header. Google: gRPC internally, REST externally via API gateway. GitHub: REST v3 + GraphQL v4. Twilio: REST with versioned URLs.'}],sd_cases:[{id:'design-url-shortener',name:'Design a URL Shortener (Bitly)',category:'classic',difficulty:1,description:'Convert long URLs to short ones. Handle billions of URLs, support redirects, and track analytics.',key_components:['API: POST /shorten (long_url -> short_code), GET /{short_code} (redirect)','ID generation: base62 encoding of auto-increment counter or pre-generated random keys','Storage: key-value store (short_code -> long_url + metadata), sharded by short_code','Redirect: 301 (permanent, browser caches) vs 302 (temporary, can track clicks)','Analytics: async event stream to analytics pipeline, aggregate by time, geography, referrer'],estimates:'100M URLs/day, 10:1 read:write ratio, 10B total URLs, ~200 bytes per entry = ~2TB storage',bottlenecks:'Read-heavy — caching is critical. ID generation must be atomic and fast. Analytics must be async.'},{id:'design-chat-system',name:'Design a Chat System (WhatsApp/Slack)',category:'classic',difficulty:2,description:'Real-time messaging between users. Support one-on-one and group chats, online status, and message history.',key_components:['WebSocket for real-time message delivery','Message queue for offline users (pull on reconnect)','Database: message table partitioned by conversation_id, separate metadata service','Presence service: heartbeat with TTL in Redis, publish status changes via pub/sub','Group chat: fan-out on write (one copy per recipient) or fan-out on read (single copy, query on read)'],estimates:'50M DAU, 10K messages/sec peak, messages stored forever, 100 bytes avg = ~50TB/year',bottlenecks:'WebSocket connection management at scale. Fan-out strategy for group chats. Message ordering guarantees.'},{id:'design-news-feed',name:'Design a News Feed (Twitter/Instagram)',category:'classic',difficulty:2,description:'Generate a personalized feed of posts from people you follow. Support ranking, pagination, and real-time updates.',key_components:['Fan-out on write: when user posts, push to all followers\' feeds — fast reads but expensive writes for popular users','Fan-out on read: when user requests feed, merge posts from all followees — slower reads but cheaper writes','Hybrid: fan-out on write for most users, fan-out on read for celebrities with millions of followers','Ranking: chronological (simple) or ML-based (engagement, recency, relevance)','Pagination: cursor-based (not offset-based) for consistent results as new posts arrive'],estimates:'100M DAU, 500M posts/day, avg 200 followers, feed is top 20 posts per page',bottlenecks:'Fan-out for popular users (millions of followers). Ranking computation at scale. Feed generation latency.'},{id:'design-search-autocomplete',name:'Design Search Autocomplete',category:'classic',difficulty:2,description:'Suggest search queries as the user types. Must be fast (<50ms), relevant, and update in real-time.',key_components:['Trie data structure: prefix tree for efficient prefix matching','N-gram model: store top K completions for each prefix','Ranking: by historical query frequency + personalization + freshness','Update: increment query counts in real-time, rebuild top-K periodically','Sharding: partition by prefix first letter, or by hash of prefix'],estimates:'100M queries/day, 20 characters avg, top 5 suggestions per prefix, 50ms latency requirement',bottlenecks:'Trie size for billions of queries. Update latency for trending queries. Personalization at scale.'},{id:'design-object-storage',name:'Design Object Storage (S3)',category:'advanced',difficulty:3,description:'Store and retrieve unlimited binary objects. Durability 99.999999999%, availability 99.99%.',key_components:['API: PUT/GET/DELETE object, list objects by prefix','Metadata service: maps object key to location(s), stores user metadata','Storage nodes: store actual object data, erasure-coded across multiple nodes','Erasure coding: split object into data + parity chunks — survive N failures with less overhead than full replication','Replication: replicate across availability zones, cross-region replication optional','Consistency: read-after-write for new objects, eventual consistency for overwrites'],estimates:'100B objects, 1TB/day ingestion, avg object size 100KB-1GB, 99.999999999% durability',bottlenecks:'Metadata service scalability. Garbage collection of deleted/orphaned objects. Cross-region consistency.'},{id:'design-notification-system',name:'Design a Notification System',category:'classic',difficulty:2,description:'Send push, SMS, and email notifications to millions of users. Support templates, preferences, and delivery tracking.',key_components:['Notification types: push (APNs/FCM), SMS (Twilio), email (SES/SendGrid)','Template engine: merge user data into templates, support localization','Preference service: user opt-in/out per channel and category','Rate limiting: per-user and per-channel limits to prevent notification fatigue','Delivery tracking: event stream for sent, delivered, opened, clicked','Queue: priority queue per channel, retry with exponential backoff for failures'],estimates:'10M notifications/day, 3 channels, 100ms send latency, 99.9% delivery rate',bottlenecks:'Rate limiting across distributed senders. Retry logic without double-sending. Channel-specific failure handling (APNs token invalidation).'},{id:'design-web-crawler',name:'Design a Web Crawler',category:'classic',difficulty:2,description:'Crawl the web at scale: discover, download, process, and index billions of pages.',key_components:['URL frontier: priority queue of URLs to crawl, deduplicated via Bloom filter','Downloader: fetch pages with rate limiting and politeness (respect robots.txt, crawl delays)','Parser: extract links, content, metadata from HTML','Storage: raw HTML in object storage, metadata in structured database','Scheduler: re-crawl based on page freshness and change frequency','Distributed: multiple crawler nodes, coordinate via URL frontier shared in message queue'],estimates:'10B pages, avg 100KB per page = 1PB raw data, crawl 100 pages/sec per node, 100 nodes',bottlenecks:'URL deduplication at scale. Politeness (don\'t DDoS sites). Freshness (knowing when to re-crawl). Deep web (pages not linked from anywhere).'},{id:'design-key-value-store',name:'Design a Key-Value Store (DynamoDB/Redis)',category:'advanced',difficulty:3,description:'Build a highly available, low-latency key-value store. Support tunable consistency, automatic partitioning, and replication.',key_components:['API: get(key), put(key, value), delete(key) — simple interface, complex internals','Partitioning: consistent hashing to distribute keys across nodes','Replication: replicate each key to N nodes for durability','Consistency: read-repair, anti-entropy (Merkle trees), vector clocks for conflict detection','Write path: coordinator sends to N replicas, waits for W acknowledgments (quorum write)','Read path: coordinator reads from N replicas, waits for R responses (quorum read) — R+W > N for consistency'],estimates:'1TB data, 1M reads/sec, 100K writes/sec, <10ms p99 latency',bottlenecks:'Hot keys (celebrity problem). Merkle tree comparison during anti-entropy. Vector clock growth for frequently updated keys.'},{id:'design-location-service',name:'Design a Location-Based Service (Uber/Yelp)',category:'advanced',difficulty:3,description:'Find nearby places or people within a radius. Support real-time location updates and proximity queries.',key_components:['Geohashing: encode lat/lng into a string — nearby locations share prefixes','Quadtree: recursively partition the map into quadrants — adaptive resolution','Google S2: cover geometric regions with cells — good for spatial indexing','Location updates: periodic GPS reports, update in-memory spatial index','Proximity query: find all entities within radius R of point (lat, lng)','Range vs K-nearest: \'all restaurants within 2km\' vs \'5 nearest restaurants\''],estimates:'10M active users, location update every 5 seconds, 1M nearby queries/sec',bottlenecks:'Write throughput from location updates. Spatial index maintenance. Cold start for sparse areas.'},{id:'design-video-streaming',name:'Design a Video Streaming Platform (YouTube/Netflix)',category:'advanced',difficulty:3,description:'Upload, process, store, and stream video to millions of concurrent viewers. Support adaptive bitrate, recommendations, and analytics.',key_components:['Upload: client uploads to object storage via presigned URL','Processing: transcode to multiple resolutions (1080p, 720p, 480p, 360p) using distributed workers','CDN: serve video from edge locations, adaptive bitrate streaming (HLS/DASH)','Metadata: video info, user data, interactions stored in relational + search DB','Recommendation: collaborative filtering + content-based, served from pre-computed results','Analytics: stream view events to data warehouse for reporting and ML training'],estimates:'500M hours watched/day, 500 hours uploaded/minute, 1B+ videos, 80% of traffic from CDN',bottlenecks:'Transcoding pipeline throughput. CDN cache efficiency. Live streaming latency. Recommendation relevance.'}],sd_patterns:[{id:'event-driven',name:'Event-Driven Architecture',category:'pattern',description:'Services communicate by producing and consuming events. Decouples producers from consumers and enables async processing.',when_to_use:'When you need loose coupling between services, async workflows, or real-time data pipelines.',key_benefits:['Loose coupling — producers don\'t know about consumers','Easy to add new consumers without changing producers','Natural audit trail — events are the source of truth','Enables event sourcing and CQRS'],common_pitfalls:['Event ordering across partitions','Exactly-once processing is hard','Schema evolution is tricky','Debugging distributed event flows is complex'],technologies:'Kafka, EventBridge, Pulsar, RabbitMQ'},{id:'cqrs',name:'CQRS (Command Query Responsibility Segregation)',category:'pattern',description:'Separate the write model (commands) from the read model (queries). Each can be optimized independently.',when_to_use:'When read and write workloads have very different patterns or scale requirements.',key_benefits:['Optimize reads and writes independently','Read models can be denormalized for query performance','Write models can focus on business logic and validation','Enables event sourcing'],common_pitfalls:['Increased complexity — two models to maintain','Eventual consistency between write and read models','Data synchronization logic','More infrastructure'],technologies:'EventStoreDB, Kafka + materialized views, custom read model projection'},{id:'sidecar',name:'Sidecar Pattern',category:'pattern',description:'Deploy a helper container alongside the main application. Handles cross-cutting concerns like logging, monitoring, and security.',when_to_use:'When you need to add functionality to a service without modifying its code — especially in microservices and service meshes.',key_benefits:['Language-agnostic — works with any application','Separation of concerns — infra logic out of business logic','Consistent cross-cutting concerns across services','Independent deployment and scaling'],common_pitfalls:['Resource overhead — extra container per pod','Latency from inter-process communication','Complexity in debugging two interacting processes','Sidecar must be versioned with the main app'],technologies:'Istio (Envoy sidecar), Linkerd, Consul Connect'},{id:'circuit-breaker',name:'Circuit Breaker',category:'reliability-pattern',description:'Stop making calls to a failing service. After N failures, \'open\' the circuit and return a fallback. After a timeout, try again (\'half-open\').',when_to_use:'When calling a downstream service that might fail — prevent cascading failures and give the downstream time to recover.',key_benefits:['Prevents cascading failures','Fast fail instead of waiting for timeouts','Gives failing services time to recover','Provides graceful degradation'],common_pitfalls:['Fallback must be safe and useful','Threshold tuning — too sensitive vs too tolerant','Monitoring — must alert when circuits are open','Testing — hard to test circuit breaker behavior'],technologies:'Resilience4j (Java), Polly (.NET), Hystrix (deprecated), custom implementations'},{id:'bulkhead',name:'Bulkhead Pattern',category:'reliability-pattern',description:'Isolate different parts of the system so that a failure in one doesn\'t take down the whole thing. Like watertight compartments in a ship.',when_to_use:'When you have shared resources (thread pools, connections, CPU) that could be exhausted by one workload and affect others.',key_benefits:['Failure isolation — one bad workload doesn\'t affect others','Resource guarantees — each partition gets a fair share','Clear ownership — easier to attribute resource usage','Predictable degradation — known failure modes'],common_pitfalls:['Resource waste — reserved but unused capacity','Tuning partition sizes is hard','Cross-partition requests need special handling','More complex resource management'],technologies:'Thread pool isolation, Kubernetes resource limits, connection pool per downstream'},{id:'saga',name:'Saga Pattern',category:'pattern',description:'Manage distributed transactions across services using a sequence of local transactions, each with a compensating action for rollback.',when_to_use:'When you need transaction-like behavior across multiple services that each own their own data.',key_benefits:['No distributed locks — each service handles its own transaction','Services remain loosely coupled','Compensating actions provide rollback semantics','Supports long-running transactions'],common_pitfalls:['Compensating actions must be correct and idempotent','Orchestration vs choreography trade-off','Debugging is hard — which step failed?','No isolation — other transactions may see partial state'],technologies:'Temporal, Camunda, AWS Step Functions, custom orchestration with Kafka'},{id:'strangler-fig',name:'Strangler Fig Pattern',category:'pattern',description:'Gradually migrate a monolith by building new functionality as separate services and routing traffic away from the old system, piece by piece.',when_to_use:'When migrating from a monolith to microservices — don\'t rewrite everything at once.',key_benefits:['Incremental migration — low risk at each step','Old and new systems coexist during transition','Can stop and reverse at any point','Team can learn and adapt as they go'],common_pitfalls:['Data synchronization between old and new systems','Routing complexity — which requests go where?','Testing both systems in parallel','Feature parity between old and new takes time'],technologies:'API gateway for routing, feature flags for gradual rollout, dual-write for data migration'},{id:'backpressure',name:'Backpressure',category:'reliability-pattern',description:'When a downstream system is slow, propagate that pressure upstream so fast producers don\'t overwhelm slow consumers.',when_to_use:'When producers can generate data faster than consumers can process it — which is almost always in distributed systems.',key_benefits:['Prevents buffer overflows and out-of-memory errors','Natural flow control — system self-regulates','Protects downstream from being overwhelmed','Graceful degradation under load'],common_pitfalls:['Backpressure must propagate all the way to the source','Deadlocks if both sides wait on each other','Latency increases when backpressure is active','Must distinguish between temporary slowdown and permanent failure'],technologies:'Reactive streams (RxJS, Project Reactor), Kafka consumer lag monitoring, explicit queue depth checks'}]};
var episodes=[];
var playlists=[];
var currentPlaylist='all';
var displayedEps=5;
var currentTab='home';
var currentEpId=null;
var playlistIdx=-1;
var loopMode='off';
var isPlaying=false;
var isPlayerOpen=false;
var isPlaylistOpen=false;
var activeCategory='all';
var sdCategory='all';
var searchQuery='';
var expandedPlaylists={};

var catMap={self_description:"self-description",opinion_stating:"opinion-stating",transitional:"transitional",emphasis:"emphasis",refining:"refining",bridging:"bridging",impact:"impact",elaboration:"elaboration",thinking_time:"thinking-time",structural:"structural",analysis:"analysis"};
var catLabels={self_description:"Self-Description",opinion_stating:"Opinion",transitional:"Transitional",emphasis:"Emphasis",refining:"Refining",bridging:"Bridging",impact:"Impact",elaboration:"Elaboration",thinking_time:"Thinking Time",structural:"Structural",analysis:"Analysis"};
var catKeys=Object.keys(catLabels);
var sdCatLabels={fundamentals:"Fundamentals",infrastructure:"Infrastructure",data:"Data",architecture:"Architecture",reliability:"Reliability","reliability-pattern":"Reliability Patterns",pattern:"Arch Patterns",classic:"Classic",advanced:"Advanced"};

var audio=null;

function getAudio(){
  if(!audio)audio=document.getElementById('spAudio');
  return audio;
}

function switchTab(t){
  currentTab=t;
  document.querySelectorAll('.tab').forEach(function(el){el.classList.remove('on')});
  document.getElementById('tab-'+t).classList.add('on');
  document.querySelectorAll('.nav-item').forEach(function(el){el.classList.toggle('on',el.dataset.tab===t)});
  document.getElementById('appContent').scrollTop=0;
  if(t==='patterns')renderPatterns();
  if(t==='frameworks')renderFrameworks();
  if(t==='practice')renderPractice();
  if(t==='playlists')renderPlaylistsTab();
  history.replaceState(null,'','#'+t);
}

function toggleSearch(){
  var sb=document.getElementById('searchBar');
  var showing=sb.style.display==='none';
  sb.style.display=showing?'block':'none';
  if(showing)document.getElementById('searchInput').focus();
  else{document.getElementById('searchInput').value='';searchQuery='';doSearch('');}
}

function doSearch(q){
  searchQuery=q.toLowerCase().trim();
  if(currentTab==='home')renderHome();
  else if(currentTab==='patterns')renderPatterns();
  else if(currentTab==='frameworks')renderFrameworks();
  else if(currentTab==='practice')renderPractice();
  else if(currentTab==='playlists')renderPlaylistsTab();
}

function fmtTime(s){
  if(!s||isNaN(s))return'0:00';
  var m=Math.floor(s/60),sec=Math.floor(s%60);
  return m+':'+(sec<10?'0':'')+sec;
}

function getActiveEpisodes(){
  return episodes.filter(function(ep){return !ep.archived});
}

function getPlaylistEpisodes(pid){
  if(pid==='all')return getActiveEpisodes();
  var pl=null;
  for(var i=0;i<playlists.length;i++){if(playlists[i].id===pid){pl=playlists[i];break;}}
  if(!pl)return[];
  return episodes.filter(function(ep){return pl.episode_ids.indexOf(ep.id)!==-1});
}

function findLocalIdx(epList,ep){
  for(var i=0;i<epList.length;i++){if(epList[i].id===ep.id)return i;}
  return-1;
}

function playIdx(idx,epList){
  if(idx<0||idx>=episodes.length)return;
  var ep=episodes[idx];
  playlistIdx=idx;
  currentEpId=ep.id;
  if(ep.playlist_id)currentPlaylist=ep.playlist_id;
  var a=getAudio();
  if(ep.file_url)a.src=ep.file_url;
  a.play().then(function(){isPlaying=true;updateAllPlayerUI();}).catch(function(){});
  isPlaying=true;
  updateAllPlayerUI();
  var sp=document.getElementById('stickyPlayer');
  sp.classList.add('on');
  sp.classList.add('playing');
  document.getElementById('appContent').classList.add('has-player');
  document.getElementById('spTitle').textContent='#'+ep.id+': '+(ep.title||ep.pattern);
  updatePlaylistLabel();
  updateAllPlayerUI();
  updateFeedbackUI(ep.id);
  updateNowPlayingCards();
  renderPlaylist();
  localStorage.setItem('lastPlaylistIdx',String(idx));
  localStorage.setItem('lastPlaylist',currentPlaylist);
}

function playEpisode(idx){playIdx(idx);}

function playPlaylist(pid){
  var epList=getPlaylistEpisodes(pid);
  if(!epList.length)return;
  currentPlaylist=pid;
  var globalIdx=episodes.indexOf(epList[0]);
  playIdx(globalIdx);
}

function updatePlaylistLabel(){
  var label=document.getElementById('spPlaylistLabel');
  if(!label)return;
  var pl=null;
  for(var i=0;i<playlists.length;i++){if(playlists[i].id===currentPlaylist){pl=playlists[i];break;}}
  label.textContent=pl?pl.name:'All Episodes';
  label.style.display=pl?'block':'none';
}

function togglePlay(e){
  if(e)e.stopPropagation();
  var a=getAudio();
  if(!a.src||!playlistIdx&&playlistIdx!==0)return;
  if(a.paused){a.play().catch(function(){});isPlaying=true;updateAllPlayerUI();}
  else{a.pause();isPlaying=false;updateAllPlayerUI();}
}

function playNext(e){
  if(e)e.stopPropagation();
  var epList=getPlaylistEpisodes(currentPlaylist);
  if(!epList.length)return;
  var localIdx=-1;
  for(var i=0;i<epList.length;i++){if(epList[i].id===currentEpId){localIdx=i;break;}}
  if(localIdx<epList.length-1){var gIdx=episodes.indexOf(epList[localIdx+1]);playIdx(gIdx);}
  else if(loopMode==='all'){var gIdx=episodes.indexOf(epList[0]);playIdx(gIdx);}
}

function playPrev(){
  var epList=getPlaylistEpisodes(currentPlaylist);
  if(!epList.length)return;
  var localIdx=-1;
  for(var i=0;i<epList.length;i++){if(epList[i].id===currentEpId){localIdx=i;break;}}
  var a=getAudio();
  if(a.currentTime>3){a.currentTime=0;return;}
  if(localIdx>0){var gIdx=episodes.indexOf(epList[localIdx-1]);playIdx(gIdx);}
  else if(loopMode==='all'){var gIdx=episodes.indexOf(epList[epList.length-1]);playIdx(gIdx);}
  else{a.currentTime=0;}
}

function seekRel(sec){
  var a=getAudio();
  if(a.duration)a.currentTime=Math.max(0,Math.min(a.duration,a.currentTime+sec));
}

function seekFromSlider(val){
  var a=getAudio();
  if(a.duration)a.currentTime=(val/1000)*a.duration;
}

function seekFromMiniEvent(e){
  var bar=e.currentTarget;
  var rect=bar.getBoundingClientRect();
  var pct=(e.clientX-rect.left)/rect.width;
  var a=getAudio();
  if(a.duration)a.currentTime=pct*a.duration;
}

function cycleLoopMode(){
  if(loopMode==='off')loopMode='all';
  else if(loopMode==='all')loopMode='one';
  else loopMode='off';
  updateLoopUI();
  localStorage.setItem('loopMode',loopMode);
}

function openPlayer(){
  if(playlistIdx<0)return;
  isPlayerOpen=true;
  document.getElementById('fullPlayer').classList.add('open');
  updateAllPlayerUI();
  renderPlaylist();
}

function closePlayer(){
  isPlayerOpen=false;
  document.getElementById('fullPlayer').classList.remove('open');
}

function togglePlaylist(){
  isPlaylistOpen=!isPlaylistOpen;
  var panel=document.getElementById('fpPlaylist');
  var toggle=document.querySelector('.fp-playlist-toggle');
  panel.classList.toggle('expanded',isPlaylistOpen);
  toggle.classList.toggle('expanded',isPlaylistOpen);
}

function updateAllPlayerUI(){
  var sp=document.getElementById('stickyPlayer');
  var fp=document.getElementById('fullPlayer');
  var a=getAudio();
  var ep=episodes[playlistIdx]||null;

  sp.classList.toggle('playing',isPlaying);
  fp.classList.toggle('playing',isPlaying);

  var playSvg='<polygon points="5 3 19 12 5 21 5 3" class="play-icon"/>';
  var pauseSvg='<rect x="6" y="4" width="4" height="16" class="pause-icon"/><rect x="14" y="4" width="4" height="16" class="pause-icon"/>';

  document.getElementById('spPlayIcon').innerHTML=isPlaying?pauseSvg:playSvg;
  document.getElementById('fpPlayIcon').innerHTML=isPlaying?pauseSvg:playSvg;

  if(ep){
    document.getElementById('fpTitle').textContent='#'+ep.id+': '+(ep.title||ep.pattern);
    document.getElementById('fpSub').textContent=ep.date+' \u00B7 '+(ep.duration||'~5 min');
    document.getElementById('fpEpNum').textContent='#'+ep.id;
    document.getElementById('fpEpPattern').textContent=ep.pattern||'';
  }

  var cur=a.currentTime||0,dur=a.duration||0;
  var pct=dur>0?(cur/dur)*100:0;
  document.getElementById('spProgressFill').style.width=pct+'%';
  document.getElementById('fpSeek').value=dur>0?Math.floor((cur/dur)*1000):0;
  document.getElementById('fpTimeCurrent').textContent=fmtTime(cur);
  document.getElementById('fpTimeDuration').textContent=dur>0?fmtTime(dur):'--:--';

  updateLoopUI();
  updateNowPlayingCards();
}

function updateLoopUI(){
  var btn=document.getElementById('fpLoopBtn');
  var label=document.getElementById('fpLoopLabel');
  btn.classList.remove('on','loop-one');
  if(loopMode==='off'){label.textContent='Loop off';}
  else if(loopMode==='all'){btn.classList.add('on');label.textContent='Loop all';}
  else if(loopMode==='one'){btn.classList.add('on','loop-one');label.textContent='Repeat 1';}
}

function updateNowPlayingCards(){
  document.querySelectorAll('.ep-card').forEach(function(card){
    var epId=card.dataset.epid;
    if(epId&&String(epId)===String(currentEpId)&&isPlaying)card.classList.add('now-playing');
    else card.classList.remove('now-playing');
  });
}

function renderPlaylist(){
  var list=document.getElementById('fpPlaylistList');
  var count=document.getElementById('fpPlaylistCount');
  var epList=getPlaylistEpisodes(currentPlaylist);
  if(!epList.length){list.innerHTML='<div style="text-align:center;padding:20px;color:var(--t3);font-size:13px">No episodes loaded</div>';count.textContent='0 episodes';return;}
  count.textContent=epList.length+' episodes';
  var pl=null;
  for(var i=0;i<playlists.length;i++){if(playlists[i].id===currentPlaylist){pl=playlists[i];break;}}
  var html='';
  if(pl)html+='<div class="fp-pl-header">'+pl.name+'</div>';
  epList.forEach(function(ep){
    var isCurrent=ep.id===currentEpId;
    var globalIdx=episodes.indexOf(ep);
    html+='<div class="fp-pl-item'+(isCurrent?' now-playing':'')+'" onclick="playIdx('+globalIdx+')">'+
      '<div class="fp-pl-num">'+ep.id+'</div>'+
      '<div class="fp-pl-info"><div class="fp-pl-title">'+(ep.title||ep.pattern)+'</div>'+
      '<div class="fp-pl-meta">'+ep.date+' \u00B7 '+(ep.duration||'~5 min')+'</div></div>'+
      (isCurrent?'<span class="fp-pl-now-badge">NOW</span>':'')+
      '</div>';
  });
  list.innerHTML=html;
  if(!isPlaylistOpen){
    isPlaylistOpen=true;
    var panel=document.getElementById('fpPlaylist');
    var toggle=document.querySelector('.fp-playlist-toggle');
    panel.classList.add('expanded');
    toggle.classList.add('expanded');
  }
  var currentEl=list.querySelector('.now-playing');
  if(currentEl)setTimeout(function(){currentEl.scrollIntoView({block:'center',behavior:'smooth'})},100);
}

function setupAudioEvents(){
  var a=getAudio();
  a.addEventListener('timeupdate',function(){
    if(isPlayerOpen||document.getElementById('stickyPlayer').classList.contains('on')){
      var cur=a.currentTime||0,dur=a.duration||0;
      var pct=dur>0?(cur/dur)*100:0;
      document.getElementById('spProgressFill').style.width=pct+'%';
      if(isPlayerOpen){
        document.getElementById('fpSeek').value=dur>0?Math.floor((cur/dur)*1000):0;
        document.getElementById('fpTimeCurrent').textContent=fmtTime(cur);
      }
    }
  });
  a.addEventListener('loadedmetadata',function(){
    if(isPlayerOpen)document.getElementById('fpTimeDuration').textContent=fmtTime(a.duration);
  });
  a.addEventListener('ended',function(){
    if(loopMode==='one'){a.currentTime=0;a.play().catch(function(){});return;}
    var epList=getPlaylistEpisodes(currentPlaylist);
    var localIdx=-1;
    for(var i=0;i<epList.length;i++){if(epList[i].id===currentEpId){localIdx=i;break;}}
    if(localIdx<epList.length-1){var gIdx=episodes.indexOf(epList[localIdx+1]);playIdx(gIdx);return;}
    if(loopMode==='all'){var gIdx=episodes.indexOf(epList[0]);playIdx(gIdx);return;}
    isPlaying=false;
    updateAllPlayerUI();
  });
  a.addEventListener('play',function(){isPlaying=true;updateAllPlayerUI();});
  a.addEventListener('pause',function(){isPlaying=false;updateAllPlayerUI();});
}

function setupSwipeClose(){
  var handle=document.getElementById('fpDragHandle');
  var fp=document.getElementById('fullPlayer');
  var startY=0,dragging=false;
  handle.addEventListener('touchstart',function(e){startY=e.touches[0].clientY;dragging=true;},{passive:true});
  fp.addEventListener('touchstart',function(e){
    if(e.target.closest('.fp-playlist-list')||e.target.closest('.fp-seek')||e.target.closest('.fp-ctrl')||e.target.closest('.fp-loop-btn')||e.target.closest('.fp-playlist-toggle')||e.target.closest('.fp-pl-item'))return;
    startY=e.touches[0].clientY;dragging=true;
  },{passive:true});
  fp.addEventListener('touchmove',function(e){
    if(!dragging)return;
    var dy=e.touches[0].clientY-startY;
    if(dy>0)fp.style.transform='translateY('+dy+'px)';
  },{passive:true});
  fp.addEventListener('touchend',function(e){
    if(!dragging)return;
    dragging=false;
    var dy=e.changedTouches[0].clientY-startY;
    if(dy>80){closePlayer();}
    fp.style.transform='';
  },{passive:true});
}

function updateFeedbackUI(epId){
  var v=localStorage.getItem('feedback-'+epId);
  document.querySelectorAll('.fb-btn[data-ep="'+epId+'"]').forEach(function(btn){
    var r=btn.dataset.rating;
    if(v===r)btn.classList.add(v==='good'?'voted':'voted-bad');
    else btn.classList.remove('voted','voted-bad');
  });
  document.querySelectorAll('.fb-status[data-ep="'+epId+'"]').forEach(function(el){
    if(v){el.textContent=v==='good'?'Found useful':'Noted';el.classList.add('show');}
    else el.classList.remove('show');
  });
}

async function vote(epId,rating){
  var existing=localStorage.getItem('feedback-'+epId);if(existing)return;
  try{
    await fetch('/api/feedback',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({episode:epId,rating:rating,date:new Date().toISOString().split('T')[0]})});
    localStorage.setItem('feedback-'+epId,rating);updateFeedbackUI(epId);
    toast(rating==='good'?'Marked as useful':'Noted, thanks for the feedback');
  }catch(_){toast('Failed to save feedback')}
}

function toast(m){var t=document.getElementById('toast');t.textContent=m;t.classList.add('on');setTimeout(function(){t.classList.remove('on')},2000)}

function renderHero(){
  var active=getActiveEpisodes();
  var ep=active[0];if(!ep)return;
  document.getElementById('heroArea').innerHTML=
    '<div class="hero-section"><div class="hero-label">Latest Episode</div>'+
    '<div class="hero-title">#'+ep.id+': '+(ep.title||ep.pattern)+'</div>'+
    '<div class="hero-sub">'+ep.date+' \u00B7 '+(ep.duration||'~5 min')+' \u00B7 '+(ep.tip||'Daily practice')+'</div>'+
    '<button class="hero-play" onclick="playEpisode(episodes.indexOf(episodes.filter(function(e){return e.id==='+ep.id+'})[0]))"><svg viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg> Play Episode</button></div>';
}

function renderStats(){
  var pc=CONTENT.patterns.length,tc=CONTENT.tips.length,sdc=CONTENT.sd_concepts.length+CONTENT.sd_cases.length+CONTENT.sd_patterns.length,prc=CONTENT.prompts.length;
  var active=getActiveEpisodes().length;
  document.getElementById('statsArea').innerHTML=
    '<div class="stat-row">'+
    '<div class="stat-card"><div class="stat-num">'+pc+'</div><div class="stat-label">Patterns</div></div>'+
    '<div class="stat-card"><div class="stat-num">'+tc+'</div><div class="stat-label">Frameworks</div></div>'+
    '<div class="stat-card"><div class="stat-num">'+sdc+'</div><div class="stat-label">Sys Design</div></div>'+
    '<div class="stat-card"><div class="stat-num">'+active+'</div><div class="stat-label">Episodes</div></div></div>';
}

function renderEpisode(ep,idx){
  var v=localStorage.getItem('feedback-'+ep.id);
  var isNP=String(ep.id)===String(currentEpId)&&isPlaying;
  return '<div class="card ep-card'+(isNP?' now-playing':'')+'" data-epid="'+ep.id+'"><div class="ep-top"><div class="ep-num">'+ep.id+'</div><div class="ep-meta">'+
    '<span class="ep-date">'+ep.date+'</span><span class="ep-dur">'+(ep.duration||'~5 min')+'</span></div></div>'+
    '<div class="ep-title">'+ep.title+'</div><div class="ep-pattern">'+(ep.pattern||'')+'</div>'+
    '<div class="ep-desc">'+(ep.description||'')+'</div><div class="ep-actions">'+
    '<button class="play-btn" onclick="playEpisode('+idx+')"><svg viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg> Play</button>'+
    '<div class="feedback-row"><span class="fl">Useful?</span>'+
    '<button class="fb-btn '+(v==='good'?'voted':'')+'" data-ep="'+ep.id+'" data-rating="good" onclick="vote('+ep.id+',\'good\')">\uD83D\uDC4D</button>'+
    '<button class="fb-btn '+(v==='bad'?'voted-bad':'')+'" data-ep="'+ep.id+'" data-rating="bad" onclick="vote('+ep.id+',\'bad\')">\uD83D\uDC4E</button>'+
    '<span class="fb-status '+(v?'show':'')+'" data-ep="'+ep.id+'">'+(v==='good'?'Found useful':v==='bad'?'Noted':'')+'</span></div></div></div>';
}

function getPlaylistIcon(id){
  var icons={'compilations':'🎯','self-intro':'🎤','prepared-qa':'❓','sd-think-aloud':'🧠','sd-estimation':'🔢','sd-mock-interviews':'🎭','sd-deep-dive':'🎧','sd-youtube':'📺','sd-concepts':'💿','sd-cases':'🏗️','sd-patterns':'🔗','interview-patterns':'💬'};
  return icons[id]||'🎵';
}

function togglePlaylistSection(pid){
  if(expandedPlaylists[pid]===false)expandedPlaylists[pid]=true;
  else expandedPlaylists[pid]=false;
  renderHome();
}

function renderHome(){
  renderHero();
  renderStats();
  var area=document.getElementById('playlistArea');
  if(!playlists.length){area.innerHTML='';return;}

  var html='';
  var order=['sd-think-aloud','sd-estimation','sd-mock-interviews','sd-youtube','sd-deep-dive','compilations','self-intro','prepared-qa','interview-patterns'];
  var sorted=order.map(function(id){for(var i=0;i<playlists.length;i++){if(playlists[i].id===id)return playlists[i];}return null;}).filter(Boolean);
  var remaining=playlists.filter(function(p){return order.indexOf(p.id)===-1;});
  var all=sorted.concat(remaining);

  all.forEach(function(pl){
    var epList=episodes.filter(function(ep){return pl.episode_ids.indexOf(ep.id)!==-1});
    var isExpanded=expandedPlaylists[pl.id]!==false;
    var isArchive=pl.id==='interview-patterns';

    html+='<div class="playlist-section'+(isArchive?' archived':'')+'">';
    html+='<div class="playlist-header" onclick="togglePlaylistSection(\''+pl.id+'\')">';
    html+='<span class="playlist-icon">'+getPlaylistIcon(pl.id)+'</span>';
    html+='<span class="playlist-name">'+pl.name+'</span>';
    html+='<span class="playlist-count">'+epList.length+'</span>';
    html+='<svg class="playlist-chevron'+(isExpanded?' expanded':'')+'" viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg>';
    html+='</div>';

    html+='<div class="playlist-body'+(isExpanded?' expanded':'')+'">';
    if(!isArchive){
      html+='<button class="playlist-play-all" onclick="event.stopPropagation();playPlaylist(\''+pl.id+'\')"><svg viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg> Play All</button>';
    }
    epList.forEach(function(ep){
      var globalIdx=episodes.indexOf(ep);
      html+=renderEpisode(ep,globalIdx);
    });
    html+='</div></div>';
  });
  area.innerHTML=html;
}

function renderPlaylistsTab(){
  var area=document.getElementById('playlistsTabList');
  if(!playlists.length){area.innerHTML='<div class="empty-state"><div class="empty-icon">\uD83C\uDFB5</div><div class="empty-title">No playlists</div></div>';return;}
  var order=['sd-think-aloud','sd-estimation','sd-mock-interviews','sd-youtube','sd-deep-dive','compilations','self-intro','prepared-qa','interview-patterns'];
  var sorted=order.map(function(id){for(var i=0;i<playlists.length;i++){if(playlists[i].id===id)return playlists[i];}return null;}).filter(Boolean);
  var remaining=playlists.filter(function(p){return order.indexOf(p.id)===-1;});
  var all=sorted.concat(remaining);

  var html='';
  all.forEach(function(pl){
    var epList=episodes.filter(function(ep){return pl.episode_ids.indexOf(ep.id)!==-1 && !ep.archived});
    var isArchive=pl.id==='interview-patterns';
    if(searchQuery){
      var sq=searchQuery;
      epList=epList.filter(function(ep){return ep.title.toLowerCase().indexOf(sq)!==-1 || (ep.pattern||'').toLowerCase().indexOf(sq)!==-1 || (ep.description||'').toLowerCase().indexOf(sq)!==-1;});
    }
    if(!epList.length&&!isArchive)return;

    html+='<div class="pl-tab-section'+(isArchive?' archived':'')+'">';
    html+='<div class="pl-tab-header" onclick="togglePlaylistTab(\''+pl.id+'\')">';
    html+='<span class="pl-tab-icon">'+getPlaylistIcon(pl.id)+'</span>';
    html+='<div class="pl-tab-info"><div class="pl-tab-name">'+pl.name+'</div><div class="pl-tab-count">'+epList.length+' episode'+(epList.length!==1?'s':'')+'</div></div>';
    html+='<svg class="pl-tab-chevron'+(expandedPlaylists['tab-'+pl.id]?' expanded':'')+'" viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg>';
    html+='</div>';

    var isExpanded=expandedPlaylists['tab-'+pl.id]!==false;
    html+='<div class="pl-tab-body'+(isExpanded?' expanded':'')+'">';
    if(!isArchive){
      html+='<button class="pl-tab-play-all" onclick="event.stopPropagation();playPlaylist(\''+pl.id+'\')"><svg viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg> Play All</button>';
    }
    epList.forEach(function(ep){
      var globalIdx=episodes.indexOf(ep);
      var isNP=String(ep.id)===String(currentEpId)&&isPlaying;
      html+='<div class="pl-tab-ep'+(isNP?' now-playing':'')+'" onclick="playIdx('+globalIdx+')">';
      html+='<div class="pl-tab-ep-num">'+ep.id+'</div>';
      html+='<div class="pl-tab-ep-info"><div class="pl-tab-ep-title">'+(ep.title||ep.pattern)+'</div><div class="pl-tab-ep-meta">'+ep.date+' \u00B7 '+(ep.duration||'~5 min')+'</div></div>';
      if(isNP)html+='<span class="pl-tab-ep-now">NOW</span>';
      html+='</div>';
    });
    html+='</div></div>';
  });
  area.innerHTML=html;
}

function togglePlaylistTab(pid){
  var key='tab-'+pid;
  if(expandedPlaylists[key]===false)expandedPlaylists[key]=true;
  else expandedPlaylists[key]=false;
  renderPlaylistsTab();
}

function renderCatChips(){
  var chips=document.getElementById('catChips');
  var html='<button class="cat-chip '+(activeCategory==='all'?'on':'')+'" onclick="filterCategory(\'all\')">All</button>';
  catKeys.forEach(function(k){html+='<button class="cat-chip '+(activeCategory===k?'on':'')+'" onclick="filterCategory(\''+k+'\')">'+catLabels[k]+'</button>';});
  chips.innerHTML=html;
}

function filterCategory(cat){activeCategory=cat;renderCatChips();renderPatterns();}

function renderPatterns(){
  renderCatChips();
  var list=document.getElementById('patternsList'),pats=CONTENT.patterns;
  if(activeCategory!=='all'){var mapped=catMap[activeCategory]||activeCategory;pats=pats.filter(function(p){return p.category===mapped});}
  if(searchQuery){var sq=searchQuery;pats=pats.filter(function(p){return p.phrase.toLowerCase().indexOf(sq)!==-1||p.explanation.toLowerCase().indexOf(sq)!==-1||p.when_to_use.toLowerCase().indexOf(sq)!==-1});}
  if(!pats.length){list.innerHTML='<div class="empty-state"><div class="empty-icon">\uD83D\uDD0D</div><div class="empty-title">No patterns found</div></div>';return;}
  var html='',lastCat='';
  pats.forEach(function(p){
    var dc='';for(var k in catMap){if(catMap[k]===p.category){dc=k;break;}}if(!dc)dc=p.category;
    if(dc!==lastCat&&activeCategory==='all'){html+='<div class="sect-header">'+(catLabels[dc]||dc)+' <span class="sect-count">'+pats.filter(function(x){return x.category===p.category}).length+'</span></div>';lastCat=dc;}
    var ds='';for(var d=0;d<3;d++)ds+=d<p.difficulty?'\u2605':'\u2606';
    html+='<div class="pat-card"><div class="pat-phrase">'+p.phrase+'</div><div class="pat-cat">'+dc.replace(/_/g,' ')+' \u00B7 '+ds+'</div><div class="pat-when">'+p.when_to_use+'</div>';
    if(p.examples&&p.examples.length){
      html+='<details><summary>Show '+p.examples.length+' example'+(p.examples.length>1?'s':'')+'</summary>';
      p.examples.forEach(function(e){
        if(typeof e==='object')html+='<div class="ex-box"><div class="ex-ctx">'+e.ctx+'</div><div class="ex-q">'+e.q+'</div><div class="ex-w">'+e.w+'</div></div>';
        else html+='<div class="ex-box"><div class="ex-q">'+e+'</div></div>';
      });
      html+='<div style="font-size:10px;color:var(--t3);padding:4px 0">'+p.explanation+'</div></details>';
    }
    html+='</div>';
  });
  list.innerHTML=html;
}

function renderFrameworks(){
  var list=document.getElementById('frameworksList'),tips=CONTENT.tips;
  if(searchQuery){var sq=searchQuery;tips=tips.filter(function(t){return t.name.toLowerCase().indexOf(sq)!==-1||t.explanation.toLowerCase().indexOf(sq)!==-1||t.segments.join(' ').toLowerCase().indexOf(sq)!==-1});}
  if(!tips.length){list.innerHTML='<div class="empty-state"><div class="empty-icon">\uD83D\uDCCB</div><div class="empty-title">No frameworks found</div></div>';return;}
  var html='',lastCat='';
  tips.forEach(function(t){
    var cl=t.category.replace(/-/g,' ').replace(/_/g,' ');
    if(t.category!==lastCat){html+='<div class="sect-header">'+cl+'</div>';lastCat=t.category;}
    html+='<div class="fw-card"><div class="fw-top"><span class="fw-tag">'+cl+'</span></div><div class="fw-name">'+t.name+'</div><div class="fw-desc">'+t.explanation+'</div><ol>';
    t.segments.forEach(function(s){html+='<li>'+s+'</li>';});
    html+='</ol></div>';
  });
  list.innerHTML=html;
}

function renderPractice(){
  var list=document.getElementById('practiceList'),prompts=CONTENT.prompts;
  if(searchQuery){var sq=searchQuery;prompts=prompts.filter(function(p){return p.text.toLowerCase().indexOf(sq)!==-1||p.competency.toLowerCase().indexOf(sq)!==-1});}
  if(!prompts.length){list.innerHTML='<div class="empty-state"><div class="empty-icon">\uD83D\uDCDD</div><div class="empty-title">No prompts found</div></div>';return;}
  var isSD=false,behavCount=0,sdCount=0;
  prompts.forEach(function(p){if(p.competency==='system-design')sdCount++;else behavCount++;});
  var html='';
  if(behavCount)html+='<div class="sect-header">Behavioral <span class="sect-count">'+behavCount+' prompts</span></div>';
  prompts.forEach(function(p){
    if(p.competency==='system-design'&&!isSD){isSD=true;html+='<div class="sect-header">System Design <span class="sect-count">'+sdCount+' prompts</span></div>';}
    var cls=p.competency==='system-design'?'sd-case-badge advanced':'prac-comp';
    html+='<div class="prac-card"><div class="'+cls+'">'+p.competency.replace(/-/g,' ')+'</div><div class="prac-q">'+p.text+'</div>';
    if(p.framework)html+='<div class="prac-framework"><span class="prac-label">Framework</span> '+p.framework+'</div>';
    if(p.patterns&&p.patterns.length){
      html+='<div class="prac-patterns"><span class="prac-label">Patterns</span> ';
      p.patterns.forEach(function(pat,i){
        html+='<span class="prac-pat-chip">'+pat+'</span>';
      });
      html+='</div>';
    }
    html+='<details><summary>Show answer guide</summary><div class="prac-guide">';
    if(p.structure&&p.structure.length){
      html+='<div class="prac-section"><div class="prac-section-title">Answer Structure</div><ol>';
      p.structure.forEach(function(s){html+='<li>'+s+'</li>';});
      html+='</ol></div>';
    }
    if(p.sample_answer)html+='<div class="prac-section"><div class="prac-section-title">Sample Answer</div><div class="prac-sample">'+p.sample_answer+'</div></div>';
    if(p.pitfalls&&p.pitfalls.length){
      html+='<div class="prac-section"><div class="prac-section-title">Common Pitfalls</div><ul>';
      p.pitfalls.forEach(function(pi){html+='<li>'+pi+'</li>';});
      html+='</ul></div>';
    }
    if(p.hint)html+='<div class="prac-hint">'+p.hint+'</div>';
    html+='</div></details></div>';
  });
  list.innerHTML=html;
}

function renderSysDesign(){
  renderSdCatChips();
  var list=document.getElementById('sysdesignList'),html='';
  var concepts=CONTENT.sd_concepts,cases=CONTENT.sd_cases,pats=CONTENT.sd_patterns;
  if(sdCategory!=='all'){
    concepts=concepts.filter(function(c){return c.category===sdCategory});
    cases=cases.filter(function(c){return c.category===sdCategory});
    pats=pats.filter(function(p){return p.category===sdCategory});
  }
  if(searchQuery){var sq=searchQuery;
    concepts=concepts.filter(function(c){return c.name.toLowerCase().indexOf(sq)!==-1||c.description.toLowerCase().indexOf(sq)!==-1});
    cases=cases.filter(function(c){return c.name.toLowerCase().indexOf(sq)!==-1||c.description.toLowerCase().indexOf(sq)!==-1});
    pats=pats.filter(function(p){return p.name.toLowerCase().indexOf(sq)!==-1||p.description.toLowerCase().indexOf(sq)!==-1});
  }
  if(!concepts.length&&!cases.length&&!pats.length){list.innerHTML='<div class="empty-state"><div class="empty-icon">\u2699\uFE0F</div><div class="empty-title">No system design content found</div></div>';return;}
  if(concepts.length){
    html+='<div class="sect-header">Core Concepts <span class="sect-count">'+concepts.length+'</span></div>';
    concepts.forEach(function(c){
      var ds='';if(c.difficulty)for(var d=0;d<3;d++)ds+=d<c.difficulty?'\u2605':'\u2606';
      html+='<div class="sd-concept"><div class="sd-name">'+c.name+'</div><div class="sd-cat">'+c.category.replace(/-/g,' ')+(ds?' \u00B7 '+ds:'')+'</div><div class="sd-desc">'+c.description+'</div><details><summary>Deep dive</summary>';
      if(c.key_points&&c.key_points.length){html+='<dl class="sd-keys"><dt>Key Points</dt>';c.key_points.forEach(function(kp){html+='<dd>'+kp+'</dd>';});html+='</dl>';}
      if(c.trade_offs)html+='<dl class="sd-keys"><dt>Trade-offs</dt><dd>'+c.trade_offs+'</dd></dl>';
      if(c.real_examples)html+='<dl class="sd-keys"><dt>Real Examples</dt><dd>'+c.real_examples+'</dd></dl>';
      html+='</details></div>';
    });
  }
  if(cases.length){
    html+='<div class="sect-header">Case Studies <span class="sect-count">'+cases.length+'</span></div>';
    cases.forEach(function(cs){
      var badge=cs.difficulty>=3?'advanced':'classic';
      html+='<div class="sd-case"><div class="sd-case-name">'+cs.name+'</div><span class="sd-case-badge '+badge+'">'+badge+'</span><div class="sd-case-desc">'+cs.description+'</div>';
      if(cs.key_components&&cs.key_components.length){html+='<div class="sd-case-section">Key Components</div><ul>';cs.key_components.forEach(function(kc){html+='<li>'+kc+'</li>';});html+='</ul>';}
      if(cs.estimates)html+='<div class="sd-case-section">Estimates</div><div style="font-size:11px;color:var(--t2)">'+cs.estimates+'</div>';
      if(cs.bottlenecks)html+='<div class="sd-case-section">Bottlenecks</div><div style="font-size:11px;color:var(--t2)">'+cs.bottlenecks+'</div>';
      html+='</div>';
    });
  }
  if(pats.length){
    html+='<div class="sect-header">Architecture Patterns <span class="sect-count">'+pats.length+'</span></div>';
    pats.forEach(function(ap){
      html+='<div class="sd-pattern"><div class="sd-pat-name">'+ap.name+'</div><div class="sd-pat-when">Use when: '+ap.when_to_use+'</div><div class="sd-pat-desc">'+ap.description+'</div><details><summary>Details</summary>';
      if(ap.key_benefits&&ap.key_benefits.length){html+='<div class="sd-list-title">Benefits</div><ul>';ap.key_benefits.forEach(function(b){html+='<li>'+b+'</li>';});html+='</ul>';}
      if(ap.common_pitfalls&&ap.common_pitfalls.length){html+='<div class="sd-list-title">Common Pitfalls</div><ul>';ap.common_pitfalls.forEach(function(pi){html+='<li>'+pi+'</li>';});html+='</ul>';}
      if(ap.technologies)html+='<div class="sd-list-title">Technologies</div><div style="font-size:11px;color:var(--t2)">'+ap.technologies+'</div>';
      html+='</details></div>';
    });
  }
  list.innerHTML=html;
}

function renderSdCatChips(){
  var chips=document.getElementById('sdCatChips');
  var cats=['all','fundamentals','infrastructure','data','architecture','reliability','reliability-pattern','pattern','classic','advanced'];
  var html='<button class="cat-chip '+(sdCategory==='all'?'on':'')+'" onclick="filterSdCategory(\'all\')">All</button>';
  cats.slice(1).forEach(function(c){var label=sdCatLabels[c]||c.replace(/-/g,' ');html+='<button class="cat-chip '+(sdCategory===c?'on':'')+'" onclick="filterSdCategory(\''+c+'\')">'+label+'</button>';});
  chips.innerHTML=html;
}

function filterSdCategory(cat){sdCategory=cat;renderSysDesign();}

function init(){
  loopMode=localStorage.getItem('loopMode')||'off';
  updateLoopUI();

  fetch('/manifest.json').then(function(r){return r.json()}).then(function(d){
    episodes=d.episodes||[];
    playlists=d.playlists||[];
    if(!episodes.length)return;
    renderHome();

    var lastIdx=parseInt(localStorage.getItem('lastPlaylistIdx'),10);
    var lastPl=localStorage.getItem('lastPlaylist')||'all';
    if(!isNaN(lastIdx)&&lastIdx>=0&&lastIdx<episodes.length){
      playlistIdx=lastIdx;
      currentEpId=episodes[lastIdx].id;
      currentPlaylist=episodes[lastIdx].playlist_id||lastPl;
      var sp=document.getElementById('stickyPlayer');
      document.getElementById('spTitle').textContent='#'+episodes[lastIdx].id+': '+(episodes[lastIdx].pattern||episodes[lastIdx].title);
      sp.classList.add('on');
      document.getElementById('appContent').classList.add('has-player');
      updatePlaylistLabel();
    }
  }).catch(function(){});
  var hash=window.location.hash.replace('#','');
  if(hash&&document.getElementById('tab-'+hash))switchTab(hash);
}

function setupInfiniteScroll(){}

init();setupAudioEvents();setupSwipeClose();
